// Auto-generated full lesson translations (inner HTML per pane) for ta.
window.LESSON_HTML = window.LESSON_HTML || {};
window.LESSON_HTML.ta = {"day-pane-1":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-leaf\" style=\"color: var(--accent-pink);\"></i> நாள் 1: ஹிரகனா அடிப்படை\n                                    <span class=\"badge\">ஒலியனியல்</span>\n                                </div>\n                                <p>விளையாட்டுக்கு வரவேற்கிறோம். ஜப்பானிய மொழியில் மூன்று எழுத்து முறைமைகள் உள்ளன: <strong>ஹிரகனா</strong> (சொந்த வார்த்தைகளுக்கான ஒலிக்குறி எழுத்துகள்), <strong>கடகனா</strong> (வெளிநாட்டு கடன் வார்த்தைகளுக்கான ஒலிக்குறி எழுத்துகள்), மற்றும் <strong>கஞ்சி</strong> (முழு வார்த்தைகளையோ கருத்துகளையோ குறிக்கும் சீன எழுத்துகள்). இன்று முழுவதும் ஹிரகனா பற்றியது.</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">ஐந்து அடிப்படை உயிரெழுத்துகள் (a, i, u, e, o)</div>\n                                    <p>கிட்டத்தட்ட ஒவ்வொரு ஜப்பானிய ஒலியிலும் இந்த உயிரெழுத்துகளில் ஒன்று இடம்பெறும் — விதிவிலக்குகள் ん (n) மற்றும் சிறிய っ இடைநிறுத்தம் மட்டுமே. இவற்றை இவ்வாறு உச்சரிக்கவும்:</p>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>あ (a)</strong> - father என்ற வார்த்தையில் உள்ளது போல \"ah\" <button class=\"speak-btn\" data-speak=\"あ\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></li>\n                                        <li><strong>い (i)</strong> - feet என்ற வார்த்தையில் உள்ளது போல \"ee\" <button class=\"speak-btn\" data-speak=\"い\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></li>\n                                        <li><strong>う (u)</strong> - boot என்ற வார்த்தையில் உள்ளது போல \"oo\" <button class=\"speak-btn\" data-speak=\"う\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></li>\n                                        <li><strong>え (e)</strong> - red என்ற வார்த்தையில் உள்ளது போல \"eh\" <button class=\"speak-btn\" data-speak=\"え\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></li>\n                                        <li><strong>お (o)</strong> - boat என்ற வார்த்தையில் உள்ளது போல \"oh\" <button class=\"speak-btn\" data-speak=\"お\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></li>\n                                    </ul>\n                                </div>\n\n                                <h3 style=\"margin: 20px 0 10px 0; color: #fff;\">மெய்யெழுத்து தொகுப்பு முறைமை</h3>\n                                <p>மற்ற எல்லா எழுத்துகளும் மெய்யெழுத்துகளை (K, S, T, N, H, M, Y, R, W) அடிப்படை உயிரெழுத்துகளுடன் இணைத்து உருவாக்கப்படுகின்றன. உதாரணமாக, K-வரிசை: <strong>か (ka), き (ki), く (ku), け (ke), こ (ko)</strong>.</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">நாள் 1 இலக்கு</div>\n                                    <p>முழு ஹிரகனா அட்டவணையைப் பார்த்து ஒலிகளைப் பயிற்சி செய்ய <a href=\"#\" data-goto-tab=\"kana\">கானா அட்டவணைகள்</a> தாவலுக்குச் செல்லவும். பிறகு, எழுத்துகளை எழுதப் பயிற்சி செய்ய <a href=\"#\" data-goto-tab=\"canvas\">கேன்வாஸ் எழுத்துப் பயிற்சி</a> தாவலுக்குச் செல்லவும். வசதியாக உணர்ந்தபின், ஹிரகனா நிலையின் கீழ் <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a> தாவலில் உங்கள் அறிவைச் சோதிக்கவும்!</p>\n                                </div>\n                            </div>","day-pane-2":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-bolt\" style=\"color: var(--accent-pink);\"></i> நாள் 2: கடகனா மற்றும் ஒலி மாற்றிகள்\n                                    <span class=\"badge\">ஒலியனியல் பகுதி II</span>\n                                </div>\n                                <p>இன்று நீங்கள் <strong>கடகனா</strong>வையும், அடிப்படை ஒலிகளை குரல் ஒலிகளாகவும் கூட்டு ஒலிகளாகவும் மாற்றும் குறியீடுகளையும் கற்றுக்கொள்வீர்கள்.</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. கடகனா (カタカナ)</div>\n                                    <p>கடகனா, ஹிரகனாவின் அதே ஒலிகளைத்தான் குறிக்கிறது, ஆனால் கூர்மையான நேரான கோடுகளைப் பயன்படுத்துகிறது. இது வெளிநாட்டு பெயர்கள், இடங்கள் மற்றும் கடன் வார்த்தைகளுக்குப் பயன்படுத்தப்படுகிறது (உதாரணமாக, カメラ - kamera: கேமரா).</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. தகுஒன் & ஹண்டகுஒன் (ஒலி திருப்பங்கள்)</div>\n                                    <p>ஒரு ஹிரகனா அல்லது கடகனா எழுத்தின் மேல் வலது பக்கத்தில் மேற்கோள் குறிகளை (தகுதென் <strong>゛</strong>) அல்லது சிறிய வட்டங்களை (ஹண்டகுதென் <strong>゜</strong>) சேர்ப்பதன் மூலம், நீங்கள் மெய்யொலியை மாற்றுகிறீர்கள்:</p>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>K-வரிசை</strong> (か) + ゛ = <strong>G-வரிசை</strong> (が - ga)</li>\n                                        <li><strong>S-வரிசை</strong> (さ) + ゛ = <strong>Z-வரிசை</strong> (ざ - za)</li>\n                                        <li><strong>T-வரிசை</strong> (た) + ゛ = <strong>D-வரிசை</strong> (だ - da)</li>\n                                        <li><strong>H-வரிசை</strong> (は) + ゛ = <strong>B-வரிசை</strong> (ば - ba)</li>\n                                        <li><strong>H-வரிசை</strong> (は) + ゜ = <strong>P-வரிசை</strong> (ぱ - pa)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. யோஒன் (கூட்டு ஒலிகள்) & சோகுஒன் (இரட்டை மெய்யொலிகள்)</div>\n                                    <p>'i' நெடுவரிசையிலிருந்து (ki, shi, chi, முதலியன) ஹிரகனாவை, சிறிய <strong>ゃ (ya)</strong>, <strong>ゅ (yu)</strong>, <strong>ょ (yo)</strong> உடன் இணைத்து <strong>きゃ (kya)</strong> அல்லது <strong>しゅ (shu)</strong> போன்ற ஒலிகளை உருவாக்குகிறோம்.</p>\n                                    <p>ஒரு சிறிய <strong>っ (tsu)</strong> பேச்சில் ஒரு குறுகிய இரட்டை மெய்யொலி இடைநிறுத்தத்தை உருவாக்குகிறது (உதாரணமாக, さっき - sakki: கொஞ்ச நேரத்திற்கு முன்பு).</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"kana\">கானா அட்டவணைகள்</a>-இல் இந்த ஒலிகளைப் பயிற்சி செய்யுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"canvas\">கேன்வாஸ் எழுத்துப் பயிற்சி</a>-இல் அவற்றை கையால் எழுதிப் பாருங்கள்.</p>\n                                </div>\n                            </div>","day-pane-3":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-arrow-up-9-1\" style=\"color: var(--accent-pink);\"></i> நாள் 3: எண்கள் மற்றும் கஞ்சி அறிமுகம்\n                                    <span class=\"badge\">சொல்வளம்</span>\n                                </div>\n                                <p>வாழ்த்துக்கள், நீங்கள் இப்போது ஒலியனியல் அறிவு பெற்றுவிட்டீர்கள்! இப்போது உறுதியான சொல்வளத்திற்குச் செல்வோம். 1 முதல் 100 வரையிலான எண்களைக் கற்று, நமது முதல் கஞ்சி எழுத்துகளை அறிமுகப்படுத்துவோம்.</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1 முதல் 10 வரையிலான எண்கள்</div>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>எண்</th>\n                                                <th>ஹிரகனா</th>\n                                                <th>ரோமாஜி</th>\n                                                <th>கஞ்சி</th>\n                                                <th>ஒலி</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr><td>1</td><td><span class=\"ja-word\">いち</span></td><td>ichi</td><td>一</td><td><button class=\"speak-btn\" data-speak=\"いち\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>2</td><td><span class=\"ja-word\">に</span></td><td>ni</td><td>二</td><td><button class=\"speak-btn\" data-speak=\"に\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>3</td><td><span class=\"ja-word\">さん</span></td><td>san</td><td>三</td><td><button class=\"speak-btn\" data-speak=\"さん\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>4</td><td><span class=\"ja-word\">よん / し</span></td><td>yon / shi</td><td>四</td><td><button class=\"speak-btn\" data-speak=\"よん\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>5</td><td><span class=\"ja-word\">ご</span></td><td>go</td><td>五</td><td><button class=\"speak-btn\" data-speak=\"ご\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>6</td><td><span class=\"ja-word\">ろく</span></td><td>roku</td><td>六</td><td><button class=\"speak-btn\" data-speak=\"ろく\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>7</td><td><span class=\"ja-word\">なな / しち</span></td><td>nana / shichi</td><td>七</td><td><button class=\"speak-btn\" data-speak=\"なな\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>8</td><td><span class=\"ja-word\">はち</span></td><td>hachi</td><td>八</td><td><button class=\"speak-btn\" data-speak=\"はち\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>9</td><td><span class=\"ja-word\">きゅう / く</span></td><td>kyuu / ku</td><td>九</td><td><button class=\"speak-btn\" data-speak=\"きゅう\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>10</td><td><span class=\"ja-word\">じゅう</span></td><td>juu</td><td>十</td><td><button class=\"speak-btn\" data-speak=\"じゅう\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top: 10px;\"><strong>99 வரை எண்ணுவது கணிதரீதியானது:</strong></p>\n                                    <ul class=\"bullet-list\">\n                                        <li>11 = பத்து + ஒன்று = じゅういち (juu-ichi)</li>\n                                        <li>20 = இரண்டு + பத்து = にじゅう (ni-juu)</li>\n                                        <li>45 = நான்கு + பத்து + ஐந்து = よんじゅうご (yon-juu-go)</li>\n                                        <li>100 என்பது <strong>ひゃく (hyaku)</strong></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">10 அத்தியாவசிய கஞ்சி எழுத்துகள்</div>\n                                    <p>கஞ்சி முழு வார்த்தைகளையோ கருத்துகளையோ குறிக்கிறது. இந்த சித்திர எழுத்துகளைக் கற்றுக்கொள்ளுங்கள்:</p>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>கஞ்சி</th>\n                                                <th>பொருள்</th>\n                                                <th>உச்சரிப்பு</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">日</span></td><td>சூரியன் / நாள்</td><td>hi / nichi</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">月</span></td><td>நிலவு / மாதம்</td><td>tsuki / getsu</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">火</span></td><td>நெருப்பு</td><td>hi / ka</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">水</span></td><td>நீர்</td><td>mizu / sui</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">木</span></td><td>மரம் / மரப்பொருள்</td><td>ki / moku</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">金</span></td><td>தங்கம் / பணம்</td><td>kane / kin</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">土</span></td><td>பூமி / மண்</td><td>tsuchi / do</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">山</span></td><td>மலை</td><td>yama / san</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">川</span></td><td>ஆறு</td><td>kawa</td></tr>\n                                            <tr><td><span class=\"ja-word\" style=\"font-size: 1.5rem;\">人</span></td><td>மனிதன் / நபர்</td><td>hito / jin</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>இந்த எண்கள் மற்றும் கஞ்சியை <a href=\"#\" data-goto-tab=\"flashcards\">நினைவு அட்டைகள்</a> மூலம் சோதித்து, பிறகு அவற்றை <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் பயன்படுத்துங்கள்.</p>\n                                </div>\n                            </div>","day-pane-4":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-puzzle-piece\" style=\"color: var(--accent-pink);\"></i> நாள் 4: இடைச்சொற்களும் வாக்கிய அமைப்பும்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>இப்போது வாக்கியங்கள் எப்படி அமைகின்றன என்று பார்ப்போம். ஆங்கிலம் எழுவாய்-வினை-செயப்படுபொருள் அமைப்பைப் பின்பற்றுகிறது (\"I eat sushi\" — நான் சுஷி சாப்பிடுகிறேன்). ஜப்பானியம் <strong>எழுவாய்-செயப்படுபொருள்-வினை</strong> அமைப்பைப் பின்பற்றுகிறது (\"I sushi eat\" — நான் சுஷி சாப்பிடுகிறேன்).</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. சொல் வரிசை அமைப்பு</div>\n                                    <p>ஆங்கிலம்: <em>I read books.</em> (நான் புத்தகங்களைப் படிக்கிறேன்.)</p>\n                                    <p>ஜப்பானியம்: <em>わたしは ほんを よみます (Watashi wa hon o yomimasu)</em> &rarr; <strong>நான் [தலைப்பு] புத்தகம் [செயப்படுபொருள்] படிக்கிறேன்.</strong></p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. முக்கியமான இடைச்சொற்கள் (助詞)</div>\n                                    <p>இடைச்சொற்கள் என்பவை பெயர்ச்சொற்களுக்குப் பின் சேர்க்கப்படும் சிறிய சொற்கள், அவை அந்தப் பெயர்ச்சொல்லின் இலக்கணப் பங்கைக் குறிக்கின்றன:</p>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>இடைச்சொல்</th>\n                                                <th>செயல்பாடு</th>\n                                                <th>உதாரணம்</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr>\n                                                <td><span class=\"ja-word\">は (wa)</span></td>\n                                                <td>வாக்கியத்தின் முக்கிய <strong>தலைப்பை</strong> குறிக்கிறது. (\"ha\" என்று எழுதப்பட்டாலும் \"wa\" என்று உச்சரிக்கப்படும்.)</td>\n                                                <td>わたし<strong>は</strong>... (watashi wa... — நான் என்றால்...)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><span class=\"ja-word\">を (o)</span></td>\n                                                <td>செயலைப் பெறும் <strong>நேரடிச் செயப்படுபொருளை</strong> குறிக்கிறது. (\"wo\" என்று எழுதப்பட்டாலும் \"o\" என்று உச்சரிக்கப்படும்.)</td>\n                                                <td>ほん<strong>を</strong>よむ (hon o yomu — புத்தகத்தைப் படி)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><span class=\"ja-word\">に (ni)</span></td>\n                                                <td><strong>நேரத்தையோ</strong> <strong>சேருமிடத்தையோ</strong> (to/at) குறிக்கிறது.</td>\n                                                <td>にほん<strong>に</strong>いく (nihon ni iku — ஜப்பானுக்குச் செல்)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><span class=\"ja-word\">で (de)</span></td>\n                                                <td>ஒரு செயலின் <strong>இடத்தையோ</strong>, பயன்படுத்தப்படும் <strong>கருவியையோ</strong> (by/at) குறிக்கிறது.</td>\n                                                <td>レストラン<strong>で</strong>たべる (resutoran de taberu — உணவகத்தில் சாப்பிடு)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><span class=\"ja-word\">の (no)</span></td>\n                                                <td><strong>உடைமையைக்</strong> காட்டுகிறது (ஆங்கிலத்தில் apostrophe-s போன்றது).</td>\n                                                <td>わたし<strong>の</strong>ねこ (watashi no neko — என் பூனை)</td>\n                                            </tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>இந்த இடைச்சொற்களை <a href=\"#\" data-goto-tab=\"builder\">வாக்கிய அமைப்பான்</a>-இல் சரியான இடத்தில் பொருத்துங்கள், அல்லது <a href=\"#\" data-goto-tab=\"bridge\">மும்மொழி பாலம்</a>-இல் அவை மொழிகளுக்கிடையே எப்படி பொருந்துகின்றன எனப் பாருங்கள்.</p>\n                                </div>\n                            </div>","day-pane-5":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-code-commit\" style=\"color: var(--accent-pink);\"></i> நாள் 5: வினைச்சொற்களும் வடிவமாற்றமும்\n                                    <span class=\"badge\">இலக்கணம் பகுதி II</span>\n                                </div>\n                                <p>இன்று நாம் ஜப்பானிய வினைச்சொற்களையும், அவற்றை முறையான பணிவான நிலைகளுக்கு எவ்வாறு வடிவமாற்றுவது என்பதையும் கற்போம். ஜப்பானிய வடிவமாற்றம் மிகவும் ஒழுங்குமுறையானது - எழுவாய் நபரைப் பொறுத்து மாறாது (நான், நீ, அவர்கள் என அனைவருக்கும் வடிவமாற்றம் சரியாக ஒரே மாதிரியே இருக்கும்)!</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. வினைச்சொல் வகைகள்</div>\n                                    <p>அனைத்து ஜப்பானிய வினைச்சொற்களும் அவற்றின் அகராதி (அடிப்படை) வடிவத்தில் 'u' ஒலியில் முடிவடையும். அவை மூன்று வகைகளாகப் பிரிக்கப்படுகின்றன:</p>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>Ru-வினைகள் (குழு 2)</strong>: -iru அல்லது -eru இல் முடிவடையும். (உதாரணமாக, たべる - taberu: சாப்பிடுதல், みる - miru: பார்த்தல்).</li>\n                                        <li><strong>U-வினைகள் (குழு 1)</strong>: மற்ற -u ஒலிகளில் முடிவடையும். (உதாரணமாக, のむ - nomu: குடித்தல், いく - iku: செல்லுதல், はなす - hanasu: பேசுதல்).</li>\n                                        <li><strong>கவனம்:</strong> -iru/-eru இல் முடியும் ஒவ்வொரு வினையும் ru-வினை அல்ல — சிலவற்றை u-வினைகளாக மனனம் செய்யவேண்டும்: かえる (kaeru — திரும்புதல்), はしる (hashiru — ஓடுதல்), はいる (hairu — நுழைதல்), きる (kiru — வெட்டுதல்), いる (iru — தேவைப்படுதல்).</li>\n                                        <li><strong>ஒழுங்கற்ற வினைகள் (குழு 3)</strong>: இரண்டே இரண்டு! <strong>する (suru: செய்தல்)</strong> மற்றும் <strong>くる (kuru: வருதல்)</strong>.</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. பணிவான (~masu) வடிவ மாற்றம்</div>\n                                    <p>பணிவாகப் பேச, வினைச்சொற்களை <strong>~ます (~masu)</strong> விகுதியுடன் மாற்றவும். வடிவமாற்ற சூத்திரங்கள்:</p>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>குழு</th>\n                                                <th>அகராதி வடிவம்</th>\n                                                <th>பணிவான வடிவம் (உடன்பாடு)</th>\n                                                <th>பணிவான வடிவம் (எதிர்மறை)</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr>\n                                                <td><strong>Ru-வினைகள்</strong> (-ru-ஐ நீக்கி, -masu சேர்க்கவும்)</td>\n                                                <td>たべる (taberu)</td>\n                                                <td><span class=\"ja-word\">たべます</span> (tabemasu)</td>\n                                                <td><span class=\"ja-word\">たべません</span> (tabemasen)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><strong>U-வினைகள்</strong> ('u' உயிரெழுத்தை 'i' ஆக மாற்றி, -masu சேர்க்கவும்)</td>\n                                                <td>のむ (nomu)</td>\n                                                <td><span class=\"ja-word\">のみます</span> (nomimasu)</td>\n                                                <td><span class=\"ja-word\">のみません</span> (nomimasen)</td>\n                                            </tr>\n                                            <tr>\n                                                <td><strong>ஒழுங்கற்றவை</strong> (நிலையான மாற்றம்)</td>\n                                                <td>する (suru) / くる (kuru)</td>\n                                                <td><span class=\"ja-word\">します</span> / <span class=\"ja-word\">きます</span></td>\n                                                <td><span class=\"ja-word\">しません</span> / <span class=\"ja-word\">きません</span></td>\n                                            </tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. கடந்த காலப் பணிவான வடிவம்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>கடந்தகால உடன்பாடு: <strong>~ます</strong>-ஐ <strong>~ました (~mashita)</strong> என மாற்றவும். உதாரணமாக, たべました (tabemashita — நான் சாப்பிட்டேன்).</li>\n                                        <li>கடந்தகால எதிர்மறை: <strong>~ます</strong>-ஐ <strong>~ませんでした (~masendeshita)</strong> என மாற்றவும். உதாரணமாக, たべませんでした (tabemasendeshita — நான் சாப்பிடவில்லை).</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>இந்த வடிவமாற்றங்களை <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் பயன்படுத்திப் பாருங்கள், பிறகு <a href=\"#\" data-goto-tab=\"flashcards\">நினைவு அட்டைகள்</a> மூலம் சொல்வளத்தை உறுதிப்படுத்துங்கள்.</p>\n                                </div>\n                            </div>","day-pane-6":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-heart\" style=\"color: var(--accent-pink);\"></i> நாள் 6: பெயரடைகளும் தேவையான சொற்றொடர்களும்\n                                    <span class=\"badge\">உரையாடல்</span>\n                                </div>\n                                <p>இன்று நாம் ஜப்பானிய பெயரடைகளைப் பயன்படுத்தி பொருட்களை விவரிக்கக் கற்கிறோம், மேலும் ஜப்பானில் பயணம் செய்ய, உணவருந்த, மற்றும் வழிகாட்ட உதவும் அத்தியாவசிய சொற்றொடர்களைச் சேகரிக்கிறோம்.</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. இரு வகையான பெயரடைகள்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>I-பெயரடைகள்</strong>: ஹிரகனா い (i) இல் முடிவடையும். உதாரணமாக おいしい (oishii: சுவையான) அல்லது おおきい (ookii: பெரிய). இவை பெயர்ச்சொல்லுக்கு நேராக முன்னால் வரும்: おいしいすし (சுவையான சுஷி).</li>\n                                        <li><strong>Na-பெயரடைகள்</strong>: அவை விவரிக்கும் பெயர்ச்சொல்லுக்கு முன் な (na) தேவைப்படும். உதாரணமாக しずか (shizuka: அமைதியான) &rarr; しずかな部屋 (shizuka na heya: அமைதியான அறை).</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. அத்தியாவசிய தேவைச் சொற்றொடர்கள்</div>\n                                    <table class=\"grammar-table\">\n                                        <thead>\n                                            <tr>\n                                                <th>ஆங்கிலம்</th>\n                                                <th>ஜப்பானியம் (ஹிரகனா / கஞ்சி)</th>\n                                                <th>ரோமாஜி</th>\n                                                <th>ஒலி</th>\n                                            </tr>\n                                        </thead>\n                                        <tbody>\n                                            <tr><td>வணக்கம் / மதிய வணக்கம்</td><td><span class=\"ja-word\">こんにちは</span></td><td>Konnichiwa</td><td><button class=\"speak-btn\" data-speak=\"こんにちは\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>நன்றி (பணிவான)</td><td><span class=\"ja-word\">ありがとうございます</span></td><td>Arigatou gozaimasu</td><td><button class=\"speak-btn\" data-speak=\"ありがとうございます\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>மன்னிக்கவும் / வருந்துகிறேன்</td><td><span class=\"ja-word\">すみません</span></td><td>Sumimasen</td><td><button class=\"speak-btn\" data-speak=\"すみません\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>கழிப்பறை எங்கே இருக்கிறது?</td><td><span class=\"ja-word\">トイレはどこですか。</span></td><td>Toire wa doko desu ka?</td><td><button class=\"speak-btn\" data-speak=\"トイレはどこですか\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>தயவுசெய்து எனக்குத் தண்ணீர் கொடுங்கள்.</td><td><span class=\"ja-word\">お水をください。</span></td><td>Omizu o kudasai</td><td><button class=\"speak-btn\" data-speak=\"お水をください\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>இது எவ்வளவு?</td><td><span class=\"ja-word\">これはいくらですか。</span></td><td>Kore wa ikura desu ka?</td><td><button class=\"speak-btn\" data-speak=\"これはいくらですか\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>இந்த சொற்றொடர்களை <a href=\"#\" data-goto-tab=\"flashcards\">நினைவு அட்டைகள்</a> மூலம் சுயமாகச் சோதித்துக்கொள்ளுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் நேரடியாக எதிர்கொள்ளுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-7":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-trophy\" style=\"color: var(--accent-pink);\"></i> நாள் 7: உரையாடல் தேர்ச்சி வகுப்பு\n                                    <span class=\"badge\">தேர்ச்சி</span>\n                                </div>\n                                <p>இறுதி நாளுக்கு வரவேற்கிறோம். ஒலியனியல் முதல் வினைச்சொல் அமைப்புகள் வரை அனைத்து கூறுகளையும் இணைக்கும் ஒரு முழுமையான உரையாடல் சூழ்நிலையைப் பார்ப்போம்.</p>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">உணவகக் காட்சி உரையாடல்</div>\n                                    <p>கீழே உள்ள உரையாடலைப் படித்து, அதைப் பேசக் கேட்க ஒலிபெருக்கி ஐகான்களைக் கிளிக் செய்யவும்:</p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>வாடிக்கையாளர்:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">すみません、メニューをください。</span><br>\n                                    <em>Sumimasen, menyuu o kudasai.</em><br>\n                                    (மன்னிக்கவும், தயவுசெய்து ஒரு மெனுவைக் கொடுங்கள்.)\n                                    <button class=\"speak-btn\" data-speak=\"すみません、メニューをください。\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>பணியாளர்:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">はい、どうぞ。</span><br>\n                                    <em>Hai, douzo.</em><br>\n                                    (ஆம், இதோ.)\n                                    <button class=\"speak-btn\" data-speak=\"はい、どうぞ。\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>வாடிக்கையாளர்:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">これはいくらですか。</span><br>\n                                    <em>Kore wa ikura desu ka.</em><br>\n                                    (இது எவ்வளவு?)\n                                    <button class=\"speak-btn\" data-speak=\"これはいくらですか。\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>பணியாளர்:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">それは千円です。</span><br>\n                                    <em>Sore wa sen en desu.</em><br>\n                                    (அது 1000 யென்.)\n                                    <button class=\"speak-btn\" data-speak=\"それはせんえんです。\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></p>\n\n                                    <p style=\"margin-top: 15px;\"><strong>வாடிக்கையாளர்:</strong></p>\n                                    <p style=\"padding-left: 10px;\"><span class=\"ja-word\" style=\"color: #fff;\">じゃあ、これをください。</span><br>\n                                    <em>Jaa, kore o kudasai.</em><br>\n                                    (அப்படியென்றால், தயவுசெய்து இதைக் கொடுங்கள்.)\n                                    <button class=\"speak-btn\" data-speak=\"じゃあ、これをください。\"><i class=\"fa-solid fa-volume-high\"></i> கேளு</button></p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"builder\">வாக்கிய அமைப்பான்</a>-இல் உங்கள் சொந்த பதிலை உருவாக்குங்கள், பிறகு <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் முழு உரையாடலையும் நேரடியாக முயற்சி செய்யுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-8":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-link\" style=\"color: var(--accent-pink);\"></i> N4·1: Te-form (て形)\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>ஜப்பானிய இலக்கணத்தின் இணைப்புச் சொல் <strong>te-form</strong> ஆகும் — இது செயல்களை இணைக்கிறது, மேலும் கோரிக்கை, அனுமதி, தொடர் நிகழ்வு ஆகியவற்றுக்கு அடிப்படையாக அமைகிறது. இதை எப்படி உருவாக்குவது, அது என்ன செய்கிறது என்பதை இங்கே காணலாம்.</p>\n                                <p style=\"font-size:0.85rem;color:var(--text-muted);\">நினைவூட்டல்: る-verbs (குழு 2) -iru/-eru என முடியும், உதாரணமாக たべる (taberu); மீதமுள்ள அனைத்தும் う-verbs (குழு 1) ஆகும், உதாரணமாக のむ (nomu) — இது N5·5 இல் விளக்கப்பட்டுள்ளது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. இதை எப்படி உருவாக்குவது</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>வினைச்சொல் முடிவு</th><th>மாற்றம்</th><th>உதாரணம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>る-verbs</td><td>る → て</td><td>たべる → <span class=\"ja-word\">たべて</span> (taberu → tabete)</td></tr>\n                                            <tr><td>う・つ・る</td><td>→ って</td><td>かう → <span class=\"ja-word\">かって</span> (kau → katte)</td></tr>\n                                            <tr><td>む・ぶ・ぬ</td><td>→ んで</td><td>のむ → <span class=\"ja-word\">のんで</span> (nomu → nonde)</td></tr>\n                                            <tr><td>く</td><td>→ いて</td><td>かく → <span class=\"ja-word\">かいて</span> (kaku → kaite)</td></tr>\n                                            <tr><td>ぐ</td><td>→ いで</td><td>およぐ → <span class=\"ja-word\">およいで</span> (oyogu → oyoide)</td></tr>\n                                            <tr><td>す</td><td>→ して</td><td>はなす → <span class=\"ja-word\">はなして</span> (hanasu → hanashite)</td></tr>\n                                            <tr><td>ஒழுங்கற்றவை</td><td>—</td><td>する→<span class=\"ja-word\">して</span>, くる→<span class=\"ja-word\">きて</span> (suru → shite, kuru → kite)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">விதிவிலக்கு: いく → <span class=\"ja-word\">いって</span> (iku → itte) (いいて அல்ல).</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. இது என்ன செய்கிறது</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>கோரிக்கை:</strong> ～てください — <span class=\"ja-word\">みてください</span> (mite kudasai — தயவுசெய்து பாருங்கள்) <button class=\"speak-btn\" data-speak=\"みてください\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>அனுமதி:</strong> ～てもいいです — <span class=\"ja-word\">たべてもいいです</span> (tabete mo ii desu — நீங்கள் சாப்பிடலாம்) <button class=\"speak-btn\" data-speak=\"たべてもいいです\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>தொடர் நிகழ்வு / நிலை:</strong> ～ています — <span class=\"ja-word\">よんでいます</span> (yonde imasu — படித்துக் கொண்டிருக்கிறேன்) <button class=\"speak-btn\" data-speak=\"よんでいます\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>தடை:</strong> ～てはいけません — <span class=\"ja-word\">はいってはいけません</span> (haitte wa ikemasen — நீங்கள் உள்ளே நுழையக்கூடாது)</li>\n                                        <li><strong>செயல்களைத் தொடர்ச்சியாக இணைத்தல்:</strong> <span class=\"ja-word\">おきて、たべて、いきます</span> (okite, tabete, ikimasu — நான் எழுந்திருந்து, சாப்பிட்டு, செல்கிறேன்)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a> இல் te-form கேள்விகளை நேரடியாக எதிர்கொள்ளுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"builder\">வாக்கிய கட்டமைப்பாளர்</a> இல் உங்கள் சொந்த வாக்கியங்களைத் தொடர்ச்சியாக உருவாக்குங்கள்.</p>\n                                </div>\n                            </div>","day-pane-9":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-comments\" style=\"color: var(--accent-pink);\"></i> N4·2: Plain (Casual) Form (சாதாரண வடிவம்)\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>மரியாதையான ～ます வடிவம் அந்நியர்களுக்கும் முறையான சூழல்களுக்கும் பயன்படுகிறது. நண்பர்கள் மற்றும் குடும்பத்தினருடன் பேசும்போது ஜப்பானியர்கள் <strong>plain form</strong> (சாதாரண வடிவம்) பயன்படுத்துகின்றனர் — மேலும் பெரும்பாலான மேம்பட்ட இலக்கணங்களை உருவாக்க இது அவசியம்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">நிகழ்காலம்: சாதாரணமும் (plain) மரியாதையும் (polite)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>பொருள்</th><th>மரியாதை</th><th>சாதாரணம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>சாப்பிடுதல்</td><td>たべます (tabemasu)</td><td><span class=\"ja-word\">たべる</span> (taberu)</td></tr>\n                                            <tr><td>சாப்பிடாதது</td><td>たべません (tabemasen)</td><td><span class=\"ja-word\">たべない</span> (tabenai)</td></tr>\n                                            <tr><td>குடித்தல்</td><td>のみます (nomimasu)</td><td><span class=\"ja-word\">のむ</span> (nomu)</td></tr>\n                                            <tr><td>குடியாதது</td><td>のみません (nomimasen)</td><td><span class=\"ja-word\">のまない</span> (nomanai)</td></tr>\n                                            <tr><td>ஆகும் (ஒரு பொருள்)</td><td>です (desu)</td><td><span class=\"ja-word\">だ</span> (da)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">சாதாரண எதிர்மறை (～ない)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>る-verbs:</strong> る-ஐ நீக்கி ない சேர்க்கவும் — みる (miru — பார்ப்பது) → <span class=\"ja-word\">みない</span> (minai)</li>\n                                        <li><strong>う-verbs:</strong> இறுதி -u ஒலியை -a ஆக மாற்றி ない சேர்க்கவும் — のむ (nomu — குடிப்பது) → <span class=\"ja-word\">のまない</span> (nomanai) (う, わ ஆக மாறும்: かう (kau — வாங்குவது) → かわない (kawanai))</li>\n                                        <li><strong>ஒழுங்கற்றவை:</strong> する (suru — செய்வது) → <span class=\"ja-word\">しない</span> (shinai), くる (kuru — வருவது) → <span class=\"ja-word\">こない</span> (konai), ある (aru — இருப்பது) → <span class=\"ja-word\">ない</span> (nai)</li>\n                                    </ul>\n                                    <p style=\"font-size:0.85rem;color:var(--text-muted);\">குறிப்பு: பேச்சு வழக்கில் です／か நீக்கப்படும் — <span class=\"ja-word\">たべる？</span> (taberu?) (உயர்ந்த குரலோசையில்) \"சாப்பிடப் போறியா?\" எனப் பொருள்படும்.</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a> இல் மரியாதை மற்றும் சாதாரண வடிவங்களுக்கு இடையே மாறிப் பயிலுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"builder\">வாக்கிய கட்டமைப்பாளர்</a> இல் பேச்சு வழக்கு வாக்கியங்களை உருவாக்குங்கள்.</p>\n                                </div>\n                            </div>","day-pane-10":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-clock-rotate-left\" style=\"color: var(--accent-pink);\"></i> N4·3: சாதாரண இறந்தகாலமும் இறந்தகால எதிர்மறையும்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>சாதாரண இறந்தகாலம் (<strong>た-form</strong>) என்பது te-form ஐப் போலவே அமைக்கப்படுகிறது — வெறும் て/で க்குப் பதிலாக た/だ சேர்த்தால் போதும். இது பேச்சு வழக்கிற்கும், ～たことがある (செய்திருக்கிறேன்) போன்ற இலக்கணங்களுக்கும் அடிப்படையாக அமைகிறது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">இறந்தகால உறுதிமொழி (～た)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>குழு</th><th>விதி</th><th>உதாரணம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>る-verbs</td><td>る → た</td><td>たべる → <span class=\"ja-word\">たべた</span> (taberu → tabeta — சாப்பிடுதல் → சாப்பிட்டது)</td></tr>\n                                            <tr><td>う・つ・る</td><td>→ った</td><td>かう → <span class=\"ja-word\">かった</span> (kau → katta — வாங்குதல் → வாங்கியது)</td></tr>\n                                            <tr><td>む・ぶ・ぬ</td><td>→ んだ</td><td>のむ → <span class=\"ja-word\">のんだ</span> (nomu → nonda — குடித்தல் → குடித்தது)</td></tr>\n                                            <tr><td>く / ぐ</td><td>→ いた / いだ</td><td>かく → <span class=\"ja-word\">かいた</span> (kaku → kaita — எழுதுதல் → எழுதியது)</td></tr>\n                                            <tr><td>す</td><td>→ した</td><td>はなす → <span class=\"ja-word\">はなした</span> (hanasu → hanashita — பேசுதல் → பேசியது)</td></tr>\n                                            <tr><td>ஒழுங்கற்றவை</td><td>—</td><td>する→<span class=\"ja-word\">した</span>, くる→<span class=\"ja-word\">きた</span>, いく→<span class=\"ja-word\">いった</span> (suru → shita, kuru → kita, iku → itta — செய்தல்/வருதல்/செல்லுதல் → செய்தது/வந்தது/சென்றது)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">இறந்தகால எதிர்மறை (～なかった)</div>\n                                    <p>சாதாரண எதிர்மறை ～ない ஐ எடுத்து, அதன் இறுதி い-ஐ <strong>かった</strong> ஆக மாற்றவும்:</p>\n                                    <ul class=\"bullet-list\">\n                                        <li>たべない (tabenai) → <span class=\"ja-word\">たべなかった</span> (tabenakatta) (சாப்பிடவில்லை) <button class=\"speak-btn\" data-speak=\"たべなかった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>いかない (ikanai) → <span class=\"ja-word\">いかなかった</span> (ikanakatta) (செல்லவில்லை)</li>\n                                        <li>い-adjectives-க்கும் இதே விதி பொருந்தும்: たかい → <span class=\"ja-word\">たかくなかった</span> (takai → takaku nakatta — விலை உயர்ந்தது → விலை உயர்ந்ததாக இல்லை)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a> இல் இறந்தகால வடிவங்களைச் சோதித்துப் பாருங்கள், பிறகு <a href=\"#\" data-goto-tab=\"builder\">வாக்கிய கட்டமைப்பாளர்</a> இல் இறந்தகால வாக்கியங்களை உருவாக்குங்கள்.</p>\n                                </div>\n                            </div>","day-pane-11":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-list-ol\" style=\"color: var(--accent-pink);\"></i> N4·4: எண்ணிடைச்சொற்கள் (助数詞)\n                                    <span class=\"badge\">சொல்வளம்</span>\n                                </div>\n                                <p>ஜப்பானிய மொழியில் ஒவ்வொரு <em>வகையான</em> பொருளுக்கும் வெவ்வேறு எண்ணிடைச் சொற்கள் பயன்படுத்தப்படும். எது பயன்படுத்துவது எனத் தெரியாதபோது, பொதுவான <strong>つ</strong> எண்ணிடைச்சொல் (1–10) பெரும்பாலான பொருட்களுக்குப் பயன்படும்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">பொதுவான எண்ணிடைச்சொற்கள்</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>எண்ணிடைச்சொல்</th><th>பயன்படும் இடம்</th><th>உதாரணம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td><span class=\"ja-word\">～つ</span></td><td>பொதுவான பொருட்கள் (1–10)</td><td>ひとつ (hitotsu), ふたつ (futatsu), みっつ (mittsu)…</td></tr>\n                                            <tr><td><span class=\"ja-word\">～こ (個)</span></td><td>சிறிய பொருட்கள்</td><td>りんご3こ (ringo sanko — 3 ஆப்பிள்கள்)</td></tr>\n                                            <tr><td><span class=\"ja-word\">～にん (人)</span></td><td>மனிதர்கள்</td><td>3にん (san-nin) (3 பேர்)*</td></tr>\n                                            <tr><td><span class=\"ja-word\">～まい (枚)</span></td><td>தட்டையான பொருட்கள் (காகிதம், டிக்கெட்)</td><td>きっぷ2まい (kippu nimai — 2 டிக்கெட்டுகள்)</td></tr>\n                                            <tr><td><span class=\"ja-word\">～ほん (本)</span></td><td>நீளமான பொருட்கள் (பேனாக்கள், பாட்டில்கள்)</td><td>ペン1ぽん (pen ippon — 1 பேனா)</td></tr>\n                                            <tr><td><span class=\"ja-word\">～ひき (匹)</span></td><td>சிறிய விலங்குகள்</td><td>ねこ2ひき (neko nihiki — 2 பூனைகள்)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"font-size:0.85rem;color:var(--text-muted);\">* மனிதர்களுக்கான எண்ணிக்கை ஒழுங்கற்றது: 1人 <span class=\"ja-word\">ひとり</span> (hitori), 2人 <span class=\"ja-word\">ふたり</span> (futari), பிறகு 3人 さんにん (san-nin)… 本/匹 உடன் ஒலிகளும் மாறும் (いっぽん ippon, さんぼん sanbon) — இவற்றைக் கேட்டுக் கேட்டே கற்றுக் கொள்ளுங்கள்.</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"flashcards\">ஃப்ளாஷ்கார்டுகள்</a> மூலம் எண்ணிடைச்சொற்களில் உங்களைச் சோதித்துக் கொள்ளுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a> வழியாக எண்ணிக் கொண்டே செல்லுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-12":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-gift\" style=\"color: var(--accent-pink);\"></i> N4·5: கொடுத்தல் & பெறுதல்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>யார் யாருக்குக் கொடுக்கிறார்கள் என்ற <strong>திசையின்</strong> அடிப்படையில் ஜப்பானிய மொழி வினைச்சொல்லைத் தேர்ந்தெடுக்கிறது. இந்த மூன்று வினைச்சொற்களையும் தெளிவாகப் புரிந்துகொண்டால் அன்றாடப் பேச்சு வழக்கு நிறைய திறந்துவிடும்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">இந்த மூன்று வினைச்சொற்கள்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong class=\"ja-word\">あげる</strong> — நான்/யாரோ ஒருவர் <em>வெளியே நோக்கிக்</em> கொடுக்கும்போது. わたしは ともだち<strong>に</strong> プレゼントを あげる. (Watashi wa tomodachi ni purezento o ageru. — நான் என் நண்பருக்கு ஒரு பரிசு கொடுக்கிறேன்.) <button class=\"speak-btn\" data-speak=\"わたしはともだちにプレゼントをあげる\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong class=\"ja-word\">くれる</strong> — யாரோ ஒருவர் <em>எனக்குக்</em> கொடுக்கும்போது. ともだちが わたしに プレゼントを <strong>くれる</strong>. (Tomodachi ga watashi ni purezento o kureru. — என் நண்பர் எனக்கு ஒரு பரிசு கொடுக்கிறார்.) <button class=\"speak-btn\" data-speak=\"ともだちがわたしにプレゼントをくれる\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong class=\"ja-word\">もらう</strong> — நான் <em>பெறும்போது</em> (கொடுப்பவரை に／から குறிக்கும்). わたしは ともだち<strong>に</strong> プレゼントを <strong>もらう</strong>. (Watashi wa tomodachi ni purezento o morau. — நான் என் நண்பரிடமிருந்து ஒரு பரிசைப் பெறுகிறேன்.) <button class=\"speak-btn\" data-speak=\"わたしはともだちにプレゼントをもらう\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                    <p style=\"font-size:0.85rem;color:var(--text-muted);\">பொதுவான விதி: பரிசு <strong>உங்களை நோக்கி</strong> வந்தால், அது எப்போதும் くれる அல்லது もらう ஆகும் — ஒருபோதும் あげる அல்ல.</p>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"builder\">வாக்கிய கட்டமைப்பாளர்</a> இல் கொடுத்தல்-பெறுதல் வாக்கியங்களை உருவாக்குங்கள், பிறகு <a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a> இல் சரியான வினைச்சொல் தேர்வைச் சோதியுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-13":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-unlock\" style=\"color: var(--accent-pink);\"></i> N4·6: Potential Form (செய்ய முடியும்)\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p><strong>potential form</strong> என்பது \"முடியும் / செய்ய இயலும்\" எனப் பொருள்படும். ஒரு முக்கியமான திருப்பம்: செயப்படுபொருள் இடைச்சொல்லான を பொதுவாக <strong>が</strong> ஆக மாறும்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">இதை எப்படி உருவாக்குவது</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>குழு</th><th>விதி</th><th>உதாரணம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>る-verbs</td><td>る → られる</td><td>たべる (taberu) → <span class=\"ja-word\">たべられる</span> (taberareru) (சாப்பிட முடியும்)</td></tr>\n                                            <tr><td>う-verbs</td><td>-u → -eru</td><td>のむ → <span class=\"ja-word\">のめる</span> (nomeru) (குடிக்க முடியும்), かく → <span class=\"ja-word\">かける</span> (kakeru) (எழுத முடியும்)</td></tr>\n                                            <tr><td>ஒழுங்கற்றவை</td><td>—</td><td>する → <span class=\"ja-word\">できる</span> (dekiru) (செய்ய முடியும்), くる → <span class=\"ja-word\">こられる</span> (korareru) (வர முடியும்)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">を → が மாற்றம்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>にほんご<strong>を</strong>はなす (nihongo o hanasu — ஜப்பானிய மொழி பேசுதல்) → にほんご<strong>が</strong>はなせる (nihongo ga hanaseru — ஜப்பானிய மொழி பேச முடியும்) <button class=\"speak-btn\" data-speak=\"にほんごがはなせる\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>かんじ<strong>が</strong>よめる (kanji ga yomeru — kanji படிக்க முடியும்)</li>\n                                        <li>பேச்சு வழக்கில் பெரும்பாலும் ら நீக்கப்படும்: たべられる (taberareru) → <span class=\"ja-word\">たべれる</span> (tabereru) (\"ra-less\" வடிவம்). இந்த ra-nuki அன்றாடப் பேச்சில் பொதுவானது என்றாலும், எழுத்திலும் தேர்வுகளிலும் இது இன்னும் தரமற்றதாகவே கருதப்படுகிறது.</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a> இல் உங்கள் \"முடியும்\" வடிவங்களைச் சோதியுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"builder\">வாக்கிய கட்டமைப்பாளர்</a> இல் அவற்றைப் பயன்படுத்தி வாக்கியங்களை உருவாக்குங்கள்.</p>\n                                </div>\n                            </div>","day-pane-14":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-code-branch\" style=\"color: var(--accent-pink);\"></i> N3·1: நிபந்தனை வாக்கியங்கள் I — ～たら & ～と\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>N3 நிலையில் \"என்றால்/போது\" எனச் சொல்வதற்கு நான்கு வழிகள் அறிமுகமாகின்றன — <strong>～たら</strong>, <strong>～と</strong>, <strong>～ば</strong>, மற்றும் <strong>～なら</strong>. இந்தப் பாடம் இவற்றில் முதல் இரண்டைக் கற்பிக்கிறது: எல்லா சூழல்களுக்கும் ஏற்ற நெகிழ்வான ～たら, மற்றும் தானாக நிகழும் அல்லது வழக்கமான விளைவுகளைக் குறிக்கும் ～と.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～たら மற்றும் ～と அமைக்கும் முறை</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>வடிவம்</th><th>விதி</th><th>எடுத்துக்காட்டு</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>～たら</td><td>சாதாரண இறந்தகாலம் (た-வடிவம்) + ら</td><td>のむ → のんだ → <span class=\"ja-word\">のんだら</span> (nomu → nonda → nondara — குடித்தல் → குடித்தால்/குடிக்கும்போது)</td></tr>\n                                            <tr><td>～たら (い-பெயரடை)</td><td>～かった + ら</td><td>たかい → <span class=\"ja-word\">たかかったら</span> (takai → takakattara — விலை அதிகமாக இருந்தால்)</td></tr>\n                                            <tr><td>～と</td><td>சாதாரண நிகழ்காலம் (அகராதி வடிவம்) + と</td><td>まがる → <span class=\"ja-word\">まがると</span> (magaru → magaru to — திரும்பினால்/திரும்பும்போது)</td></tr>\n                                            <tr><td>～と (பெயர்ச்சொல்/な-பெயரடை)</td><td>～だ + と</td><td>しずかだ → <span class=\"ja-word\">しずかだと</span> (shizuka da → shizuka da to — அமைதியாக இருந்தால்)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. たら நெகிழ்வானது, と அப்படி இல்லை</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>～たら எந்தவொரு முதன்மை வாக்கியத்தையும் ஏற்றுக்கொள்ளும் — கோரிக்கைகள், அழைப்புகள், கட்டளைகள்: いえにかえったら、でんわしてください (ie ni kaettara, denwa shite kudasai — வீட்டுக்குச் சென்றதும், தயவுசெய்து போன் செய்யுங்கள்) <button class=\"speak-btn\" data-speak=\"いえにかえったら、でんわしてください\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>～と என்பது தானாக நிகழும் அல்லது பொதுவான விளைவுகளை விவரிக்கிறது — முதன்மை வாக்கியம் கோரிக்கையாகவோ, கட்டளையாகவோ, அழைப்பாகவோ இருக்கக் கூடாது: はるになると、さくらがさきます (haru ni naru to, sakura ga sakimasu — வசந்தகாலம் வரும்போது, செரி மலர்கள் பூக்கும்) <button class=\"speak-btn\" data-speak=\"はるになると、さくらがさきます\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>நிச்சயமாக நடக்கும் காரியங்களுக்கு இரண்டு வடிவங்களுமே \"போது\" எனப் பொருள்படும்: みぎにまがると、ぎんこうがあります (migi ni magaru to, ginkou ga arimasu — வலது புறம் திரும்பினால்/திரும்பும்போது, ஒரு வங்கி இருக்கிறது) <button class=\"speak-btn\" data-speak=\"みぎにまがると、ぎんこうがあります\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>இரு நிபந்தனை வடிவங்களையும் <a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a>-இல் பயிற்சி செய்யுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"builder\">வாக்கிய கட்டமைப்பாளர்</a>-இல் உங்கள் சொந்த என்றால்/போது வாக்கியங்களை உருவாக்குங்கள்.</p>\n                                </div>\n                            </div>","day-pane-15":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-diagram-project\" style=\"color: var(--accent-pink);\"></i> N3·2: நிபந்தனை வாக்கியங்கள் II — ～ば & ～なら\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>N3 நிலையின் நிபந்தனை வடிவங்களை மேலும் இரண்டு பூர்த்தி செய்கின்றன. <strong>～ば</strong> கற்பனையான நிபந்தனைகள், பழமொழிகள், மற்றும் எதிர்மறை \"கட்டாயங்களுக்கு\" (~must) ஏற்றது. <strong>～なら</strong> மறுபக்கத்தினர் ஏற்கெனவே சொன்ன ஒன்றுக்குப் பதிலளிக்கிறது — \"அப்படியென்றால்...\" எனும் பொருளில்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ば அமைக்கும் முறை</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>குழு</th><th>விதி</th><th>எடுத்துக்காட்டு</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>う-வினைச்சொற்கள்</td><td>-u → -e + ば</td><td>のむ → <span class=\"ja-word\">のめば</span> (nomu → nomeba — குடித்தல் → குடித்தால்)</td></tr>\n                                            <tr><td>る-வினைச்சொற்கள்</td><td>る-ஐ நீக்கிவிட்டு + れば</td><td>たべる → <span class=\"ja-word\">たべれば</span> (taberu → tabereba — சாப்பிடுதல் → சாப்பிட்டால்)</td></tr>\n                                            <tr><td>ஒழுங்கற்றவை</td><td>—</td><td>する → <span class=\"ja-word\">すれば</span>, くる → <span class=\"ja-word\">くれば</span> (suru → sureba, kuru → kureba)</td></tr>\n                                            <tr><td>い-பெயரடைகள்</td><td>い → ければ</td><td>たかい → <span class=\"ja-word\">たかければ</span> (takai → takakereba — விலை அதிகமாக இருந்தால்)</td></tr>\n                                            <tr><td>எந்த எதிர்மறை வடிவமும்</td><td>～ない → なければ</td><td>たべない → <span class=\"ja-word\">たべなければ</span> (tabenai → tabenakereba — சாப்பிடவில்லை எனில்)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">இந்த எதிர்மறை ば-வடிவம்தான் ～なければならない (\"செய்யத்தான் வேண்டும்\") எனும் கட்டாய வடிவத்தின் அடிப்படையாக அமைகிறது.</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～なら — முன்வைக்கப்பட்ட விஷயத்திற்குப் பதிலளித்தல்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>பெயர்ச்சொற்களும் な-பெயரடைகளும் நேரடியாக இணைகின்றன, だ தேவையில்லை: <span class=\"ja-word\">げんきなら</span> (genki nara — உற்சாகமாக இருந்தால்), げんきだなら என்று ஒருபோதும் வராது.</li>\n                                        <li>なら மற்றவர் இப்போதுதான் எழுப்பிய ஒரு விஷயத்திற்குப் பதிலளிக்கிறது: A: にほんへいきます。 B: にほんへいくなら、パスポートがひつようです。 (nihon e iku nara, pasupooto ga hitsuyou desu — நீங்கள் ஜப்பான் செல்லப்போவதாக இருந்தால், பாஸ்போர்ட் தேவைப்படும்) <button class=\"speak-btn\" data-speak=\"にほんへいくなら、パスポートがひつようです。\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>～たら/～と/～ば போலல்லாமல், なら-உடன் கூடிய வாக்கியத்திற்கு முன்பே விளைவு நேரத்தில் நடந்திருக்கலாம் — இது கண்டிப்பான ஒரு நிகழ்வுவரிசையை விவரிக்காமல், முன்வைக்கப்பட்ட விஷயத்தைப் பற்றிக் கருத்துத் தெரிவிக்கிறது.</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～ば～ほど — \"எவ்வளவு..., அவ்வளவு...\"</div>\n                                    <p>வினைச்சொல்லை மீண்டும் சொல்லுங்கள்: ～ば வடிவம் + சாதாரண வடிவம் + ほど.</p>\n                                    <ul class=\"bullet-list\">\n                                        <li>たべればたべるほど、ふとります (tabereba taberu hodo, futorimasu — எவ்வளவு சாப்பிடுகிறீர்களோ, அவ்வளவு கொழுப்பாகிறீர்கள்) <button class=\"speak-btn\" data-speak=\"たべればたべるほど、ふとります\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>ば மற்றும் なら-ஐ <a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a>-இல் பயிற்சி செய்யுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"bridge\">இலக்கணப் பாலம்</a>-இல் உங்கள் இலக்கணக் குறிப்புகளைச் சரிபார்க்கவும்.</p>\n                                </div>\n                            </div>","day-pane-16":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-cloud-rain\" style=\"color: var(--accent-pink);\"></i> N3·3: செயப்பாட்டு வினை (Passive) — ～られる\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>செயப்பாட்டு வினை (passive voice) என்பது, ஒரு செயல் எழுவாயின் <em>மீது</em> செய்யப்படுவதை விவரிக்கும் — ஜப்பானிய மொழி இதை ஆங்கிலத்தைவிட இன்னும் விரிவாக்கி, மற்றொருவரின் செயலால் தான் முழுமையாக எதிர்மறையாகப் பாதிக்கப்பட்டதைக் கூறப் பேச்சாளருக்கு அனுமதிக்கிறது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. செயப்பாட்டு வினையை அமைத்தல்</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>குழு</th><th>விதி</th><th>எடுத்துக்காட்டு</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>う-வினைச்சொற்கள்</td><td>-u → -a + れる (う → わ)</td><td>のむ → <span class=\"ja-word\">のまれる</span> (nomu → nomareru); かう → <span class=\"ja-word\">かわれる</span> (kau → kawareru)</td></tr>\n                                            <tr><td>う-இல் முடியும் う-வினைச்சொற்கள்</td><td>う → われる</td><td>かう → <span class=\"ja-word\">かわれる</span> (kau → kawareru — வாங்குதல் → வாங்கப்படுதல்)</td></tr>\n                                            <tr><td>る-வினைச்சொற்கள்</td><td>る-ஐ நீக்கிவிட்டு + られる</td><td>たべる → <span class=\"ja-word\">たべられる</span> (taberu → taberareru — சாப்பிடுதல் → சாப்பிடப்படுதல்)</td></tr>\n                                            <tr><td>ஒழுங்கற்றவை</td><td>—</td><td>する → <span class=\"ja-word\">される</span>, くる → <span class=\"ja-word\">こられる</span> (suru → sareru, kuru → korareru)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">குறிப்பு: る-வினைச்சொற்களின் செயப்பாட்டு வடிவமும் (passive), இயலுமை வடிவமும் (potential, N4·6) ஒரே வடிவத்தைக் கொண்டவை — சூழலைப் பொறுத்தே இவற்றை வேறுபடுத்தி அறிய முடியும்.</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. நேரடி செயப்பாட்டு வினை — செயல்புரிபவரைக் குறித்தல்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>\"~ஆல்\" எனக் குறிக்கப்படும் செயல்புரிபவர் (agent) に-ஆல் குறிக்கப்படுவார்; படைப்புசார்ந்த/ஆள்சாரா நிலைமைகளுக்கு によって பயன்படுத்தப்படும்.</li>\n                                        <li>わたしはせんせいにほめられた (watashi wa sensei ni homerareta — நான் ஆசிரியரால் பாராட்டப்பட்டேன்) <button class=\"speak-btn\" data-speak=\"わたしはせんせいにほめられた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>このほんはなつめそうせきによってかかれた (kono hon wa Natsume Souseki ni yotte kakareta — இந்தப் புத்தகம் நட்சுமெ சோசெகியால் எழுதப்பட்டது) <button class=\"speak-btn\" data-speak=\"このほんはなつめそうせきによってかかれた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. துன்பப்பாட்டுச் செயப்பாட்டு வினை (迷惑の受身)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>இது ஜப்பானிய மொழிக்கே உரிய தனித்தன்மை: நேரடிக் கருமம் (direct object) இல்லாத வினைச்சொற்கள் கூட, மற்றொருவரின் செயலால் பேச்சாளர் சிரமத்திற்கு உள்ளானதைக் காட்ட செயப்பாட்டு வடிவத்தில் பயன்படுத்தப்படலாம்.</li>\n                                        <li>あめにふられた (ame ni furareta — மழையில் நனைந்தேன் [அது தொல்லையாக இருந்தது]) <button class=\"speak-btn\" data-speak=\"あめにふられた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>ともだちにこられて、べんきょうできなかった (tomodachi ni korarete, benkyou dekinakatta — ஒரு நண்பர் [என் வீட்டுக்கு] வந்துவிட்டதால், என்னால் படிக்க முடியவில்லை)</li>\n                                        <li>ஆங்கில மொழிபெயர்ப்பு இந்த நுணுக்கத்தை அரிதாகவே பிடிக்கும் — \"X நடந்ததால் நான் சிரமப்பட்டேன்\" என்று சிந்தியுங்கள், நேரடி மொழிபெயர்ப்பாக அல்ல.</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a>-இல் செயல்புரிபவரைக் கண்டறியுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"builder\">வாக்கிய கட்டமைப்பாளர்</a>-இல் சில துன்பப்பாட்டு-செயப்பாட்டு வாக்கியங்களை நீங்களே உருவாக்குங்கள்.</p>\n                                </div>\n                            </div>","day-pane-17":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-people-arrows\" style=\"color: var(--accent-pink);\"></i> N3·4: ஏவல் வினை (Causative) மற்றும் ஏவல்-செயப்பாட்டு வினை (Causative-Passive)\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>ஏவல் வினை (causative) என்பது ஒருவரை ஏதேனும் ஒன்றைச் செய்ய வைப்பதை அல்லது செய்ய அனுமதிப்பதை விவரிக்கும். இதை செயப்பாட்டு வினையுடன் இணைத்தால் ஏவல்-செயப்பாட்டு வினை (causative-passive) கிடைக்கும்: நீங்கள் விரும்பாத ஒன்றைச் செய்யும்படி வைக்கப்படுவது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ஏவல் வினையை அமைத்தல் (～せる／させる)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>குழு</th><th>விதி</th><th>எடுத்துக்காட்டு</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>う-வினைச்சொற்கள்</td><td>-u → -a + せる (う → わ)</td><td>のむ → <span class=\"ja-word\">のませる</span> (nomu → nomaseru); かう → <span class=\"ja-word\">かわせる</span> (kau → kawaseru)</td></tr>\n                                            <tr><td>る-வினைச்சொற்கள்</td><td>る-ஐ நீக்கிவிட்டு + させる</td><td>たべる → <span class=\"ja-word\">たべさせる</span> (taberu → tabesaseru — சாப்பிடுதல் → [ஒருவரை] சாப்பிடச் செய்தல்/சாப்பிட அனுமதித்தல்)</td></tr>\n                                            <tr><td>ஒழுங்கற்றவை</td><td>—</td><td>する → <span class=\"ja-word\">させる</span>, くる → <span class=\"ja-word\">こさせる</span> (suru → saseru, kuru → kosaseru)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. \"செய்ய வைத்தல்\" vs \"செய்ய அனுமதித்தல்\" — யாருக்கு に, யாருக்கு を</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>はははこどもにやさいをたべさせた (haha wa kodomo ni yasai o tabesaseta — தாய் குழந்தையைக் காய்கறிகளை சாப்பிடச் செய்தாள்/சாப்பிட வைத்தாள்) <button class=\"speak-btn\" data-speak=\"はははこどもにやさいをたべさせた\"><i class=\"fa-solid fa-volume-high\"></i></button> — இது பிறவினை (transitive verb): கட்டாயப்படுத்தப்படும் நபர் に-ஐ பெறுவார்.</li>\n                                        <li>せんせいはがくせいをはやくかえらせた (sensei wa gakusei o hayaku kaeraseta — ஆசிரியர் மாணவர்களை சீக்கிரமாக வீட்டுக்குப் போகச் செய்தார்) — かえる என்பது தன்வினை (intransitive verb): கட்டாயப்படுத்தப்படும் நபர் を-ஐ பெறுவார்.</li>\n                                        <li>சூழலும் தொனியும்தான் \"செய்ய வைத்தல்\" (கட்டாயமான) vs \"செய்ய அனுமதித்தல்\" (அனுமதி தரும்) என்பதை தீர்மானிக்கும்: どうぞやすませてください (douzo yasumasete kudasai — தயவுசெய்து என்னை ஓய்வெடுக்க அனுமதியுங்கள்) என்பது தெளிவாக அனுமதி தரும் பொருளில் உள்ளது.</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ஏவல்-செயப்பாட்டு வினை (～させられる) — செய்யும்படி வைக்கப்படுதல்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ஏவல் வினையின் தண்டு + られる என அமையும்: たべさせる → <span class=\"ja-word\">たべさせられる</span> (tabesaseru → tabesaserareru — சாப்பிடும்படி வைக்கப்பட்டேன்).</li>\n                                        <li>う-வினைச்சொற்கள் பெரும்பாலும் ～せられる-ஐ ～される எனச் சுருக்குகின்றன: のませられる → <span class=\"ja-word\">のまされる</span> (nomaserareru → nomasareru) — இரண்டு வடிவங்களுமே சரியானவைதான்; பேச்சு வழக்கில் சுருக்கப்பட்ட வடிவமே அதிகம் பயன்படுகிறது.</li>\n                                        <li>わたしはははにやさいをたべさせられた (watashi wa haha ni yasai o tabesaserareta — நான் என் அம்மாவால் காய்கறிகளை சாப்பிடும்படி வைக்கப்பட்டேன் [எனக்கு விருப்பமில்லாமலேயே]) <button class=\"speak-btn\" data-speak=\"わたしはははにやさいをたべさせられた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a>-இல் ஏவல் வினை மற்றும் ஏவல்-செயப்பாட்டு வினை வாக்கியங்களைப் பிரித்தறியுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"flashcards\">ஃப்ளாஷ்கார்டுகள்</a> மூலம் இவ்வடிவங்களைப் பயிற்சி செய்யுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-18":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-gavel\" style=\"color: var(--accent-pink);\"></i> N3·5: மாற்றமும் முடிவுகளும்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>இந்த நான்கு வடிவங்களும் ஒரே மாதிரி தோன்றினாலும், இரண்டு அடிப்படைகளில் வேறுபடுகின்றன: <strong>なる</strong> (ஆகுதல்) தானாக நிகழும் ஒரு மாற்றத்தை விவரிக்கிறது, <strong>する</strong> (செய்தல்) என்பது வேண்டுமென்றே செய்யப்படும் ஒரு செயலை விவரிக்கிறது — மேலும் <strong>よう</strong> (ஒரு நிலை/திறன்) என்பது <strong>こと</strong> (ஒரு உண்மை/முடிவு) என்பதற்கு மாறுபட்டது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ようになる — நிலை அல்லது திறனில் ஏற்படும் மாற்றம்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>இயலுமை வடிவம்/அகராதி வடிவம் + ようになる — காலப்போக்கில் படிப்படியாக, இயற்கையாக நிகழும் மாற்றத்தைக் குறிக்கும்.</li>\n                                        <li>かんじがよめるようになった (kanji ga yomeru you ni natta — எனக்கு கஞ்சி படிக்கத் தெரிந்துவிட்டது [முன்பு தெரியாது]) <button class=\"speak-btn\" data-speak=\"かんじがよめるようになった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>まいにちにほんごをはなすようになりました (mainichi nihongo o hanasu you ni narimashita — நான் தினமும் ஜப்பானிய மொழி பேசும் பழக்கத்தை ஏற்படுத்திக் கொண்டேன்)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ことになる — மற்றவர்களால் முடிவு செய்யப்பட்டது, அல்லது ஒரு ஏற்பாடு</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>அகராதி வடிவம்/ない-வடிவம் + ことになる — சூழ்நிலைகளாலோ, ஒரு குழுவினாலோ, வேறொருவராலோ எடுக்கப்பட்ட முடிவை அறிவிக்கும் — பேச்சாளர் தனிப்பட்ட முறையில் எடுத்த முடிவு அல்ல.</li>\n                                        <li>らいげつ、とうきょうにてんきんすることになった (raigetsu, Tokyo ni tenkin suru koto ni natta — அடுத்த மாதம், நான் டோக்கியோவுக்கு இடமாற்றம் செய்யப்படுவது என முடிவாகிவிட்டது) <button class=\"speak-btn\" data-speak=\"らいげつ、とうきょうにてんきんすることになった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～ようにする／～ことにする — வேண்டுமென்றே செய்யப்படும் வடிவங்கள்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>～ようにする:</strong> அகராதி வடிவம்/ない-வடிவம் + ようにする — தொடர்ச்சியான, நினைவுபூர்வமான முயற்சி அல்லது பழக்கத்தைக் குறிக்கும். まいにちうんどうするようにしています (mainichi undou suru you ni shiteimasu — நான் தினமும் உடற்பயிற்சி செய்வதை வழக்கமாக்கிக் கொண்டிருக்கிறேன்)</li>\n                                        <li><strong>～ことにする:</strong> அகராதி வடிவம்/ない-வடிவம் + ことにする — பேச்சாளர் தன் சொந்த விருப்பப்படி எடுக்கும் ஒருமுறை மட்டுமான தனிப்பட்ட முடிவு. かいしゃをやめることにした (kaisha o yameru koto ni shita — நான் நிறுவனத்தை விட்டு வெளியேற முடிவு செய்துவிட்டேன்) <button class=\"speak-btn\" data-speak=\"かいしゃをやめることにした\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a>-இல் なる vs する-ஐ பிரித்தறியுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"bridge\">இலக்கணப் பாலம்</a>-இல் உங்கள் புரிதலைச் சரிபார்க்கவும்.</p>\n                                </div>\n                            </div>","day-pane-19":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-ear-listen\" style=\"color: var(--accent-pink);\"></i> N3·6: செவிவழிச் செய்தியும் தோற்றமும் (Hearsay & Appearance)\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>\"போல் தெரிகிறது\" அல்லது \"என்று கேள்விப்பட்டேன்\" எனச் சொல்வதற்கு நான்கு வழிகள் — இவற்றில் ஒன்றான そうだ, அது எப்படி இணைக்கப்படுகிறது என்பதைப் பொறுத்து முற்றிலும் வேறுபட்ட இரு பொருள்களைத் தரும். இணைப்பு விதியைச் சரியாகப் புரிந்துகொண்டால், மற்றவை தானாகப் புரிந்துவிடும்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. そうだ — செவிவழிச் செய்தி vs தோற்றம் (குழப்பம் வரும் இடம்)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>பொருள்</th><th>இணைவது</th><th>எடுத்துக்காட்டு</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>செவிவழிச் செய்தி (伝聞) — \"நான் கேள்விப்பட்டேன்...\"</td><td>சாதாரண வடிவம், எந்தக் காலமும் (பெயர்ச்சொல்/な-பெயரடை + だ)</td><td>あしたはあめだそうです (ashita wa ame da sou desu — நாளை மழை பெய்யும் என்று கேள்விப்பட்டேன்) <button class=\"speak-btn\" data-speak=\"あしたはあめだそうです\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>தோற்றம் (様態) — \"போலத் தெரிகிறது...\"</td><td>வினைச்சொல்லின் ます-தண்டு / பெயரடையின் தண்டு (い இல்லை, だ இல்லை)</td><td>あめがふりそうです (ame ga furisou desu — மழை பெய்யப்போவது போலத் தெரிகிறது) <button class=\"speak-btn\" data-speak=\"あめがふりそうです\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                        </tbody>\n                                    </table>\n                                    <ul class=\"bullet-list\">\n                                        <li>செவிவழிச் செய்தி そうだ, பெயர்ச்சொல்/な-பெயரடைக்கு முன் だ-ஐ ஒருபோதும் விடாது: これはぺんだそうです (kore wa pen da sou desu — இது ஒரு பேனா என்று கேள்விப்பட்டேன்).</li>\n                                        <li>தோற்ற そうだ, だ-ஐ முழுவதுமாக விட்டுவிட்டு தண்டுடன் நேரடியாக இணைகிறது: おいしい → <span class=\"ja-word\">おいしそう</span> (oishii → oishisou — சுவையாக இருப்பது போலத் தெரிகிறது); げんき → <span class=\"ja-word\">げんきそう</span> (genki → genkisou — ஆரோக்கியமாக இருப்பது போலத் தெரிகிறது).</li>\n                                        <li>இரண்டு ஒழுங்கற்ற தோற்ற-தண்டுகள்: いい → <span class=\"ja-word\">よさそう</span> (ii → yosasou, iisou அல்ல); ない → <span class=\"ja-word\">なさそう</span> (nai → nasasou).</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. らしい — இடைவெளியுடன் கூடிய செவிவழிச் செய்தி, அல்லது \"பொருத்தமான தன்மை\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>சாதாரண வடிவம் (だ இல்லாத பெயர்ச்சொல்) + らしい — கேள்விப்பட்ட ஒன்றைத் தெரிவிக்கிறது, பொதுவாக そうだ-ஐ விடவும் அதிக தூரம்/நிச்சயமற்ற தன்மையுடன், நேரடி மூலத்தை விடவும் பொதுவான வதந்தியிலிருந்து அறியப்பட்டது என்பதைக் காட்டும்.</li>\n                                        <li>たなかさんはらいげつけっこんするらしいです (Tanaka-san wa raigetsu kekkon suru rashii desu — தானகா அடுத்த மாதம் திருமணம் செய்துகொள்கிறார் என்று கேள்விப்படுகிறேன்) <button class=\"speak-btn\" data-speak=\"たなかさんはらいげつけっこんするらしいです\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>\"பொருத்தமான/அதைப் போன்றது\" எனும் பொருளும் தரும்: おとこらしい (otoko rashii — ஆண்மையான, ஒரு \"உண்மையான ஆண்\" போல்).</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. みたい & ようだ — பார்ப்பதிலிருந்து ஊகித்தல்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>இரண்டுமே கண்காணிப்பு அல்லது ஒப்பீட்டின் அடிப்படையில் \"தெரிகிறது/போலத் தோன்றுகிறது\" எனப் பொருள்படும் — みたい என்பது சாதாரண பேச்சு வழக்கு, ようだ என்பது இன்னும் முறையான/எழுத்து வடிவப் பயன்பாடு.</li>\n                                        <li>பெயர்ச்சொற்கள்/な-பெயரடைகள்: みたい நேரடியாக இணையும் (あめみたい); ようだ-க்கு の／な தேவை (あめのようだ, げんきなようだ).</li>\n                                        <li>あのひとはがくせいみたいです (ano hito wa gakusei mitai desu — அந்த நபர் ஒரு மாணவர் போலத் தெரிகிறது)</li>\n                                        <li>かれはびょうきのようだ (kare wa byouki no you da — அவன் உடல்நிலை சரியில்லாதவன் போலத் தெரிகிறான்)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a>-இல் செவிவழிச் செய்தியையும் தோற்றத்தையும் பிரித்தறியுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"flashcards\">ஃப்ளாஷ்கார்டுகள்</a> மூலம் நான்கையும் உங்களைச் சோதித்துக் கொள்ளுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-20":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-toolbox\" style=\"color: var(--accent-pink);\"></i> N3·7: て-வடிவ நீட்டிப்புகள்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>て-வடிவம் N3 நிலையிலும் தன் பயன்பாட்டைத் தொடர்கிறது — இதனுடன் おく, しまう, ある, அல்லது みる ஆகியவற்றை இணைத்தால், அன்றாடப் பேச்சில் பயன்படும் இன்னும் நான்கு நுணுக்கங்களைக் கற்றுக்கொள்ளலாம்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ておく — முன்கூட்டியே செய்து வைத்தல், அல்லது அப்படியே விட்டுவிடுதல்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>எதிர்காலப் பயனுக்காக ஏதேனும் ஒன்றை முன்கூட்டியே தயார் செய்து வைப்பதை, அல்லது அப்படியே விட்டுவிடுவதைக் குறிக்கும்.</li>\n                                        <li>ビールをかっておく (biiru o katte oku — பீரை முன்கூட்டியே வாங்கி வைத்துக்கொள் [பிறகு நடக்கும் விருந்துக்காக]) <button class=\"speak-btn\" data-speak=\"ビールをかっておく\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>சாதாரண பேச்சு வழக்கில் ～ておく, ～とく எனச் சுருக்கப்படும்: かっておく → <span class=\"ja-word\">かっとく</span> (katte oku → kattoku).</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～てしまう — முழுமையாக முடித்தல், அல்லது \"அய்யோ\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ஏதேனும் ஒன்று முழுமையாக முடிந்துவிட்டதை வலியுறுத்தும், பெரும்பாலும் வருத்தம் அல்லது தற்செயலான செயல் என்ற நுணுக்கத்துடன்.</li>\n                                        <li>しゅくだいをやってしまった (shukudai o yatte shimatta — வீட்டுப்பாடத்தை (homework) முழுவதுமாக முடித்துவிட்டேன்) <button class=\"speak-btn\" data-speak=\"しゅくだいをやってしまった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>சாதாரண சுருக்கம்: ～てしまう → ～ちゃう (அல்லது ～でしまう → ～じゃう): たべてしまう → <span class=\"ja-word\">たべちゃう</span> (tabete shimau → tabechau).</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～てある vs ～ている, மற்றும் ～てみる — \"முயற்சி செய்தல்\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>～てある</strong> (பிறவினை + ある): யாரோ ஒருவர் வேண்டுமென்றே ஏற்படுத்தி வைத்திருக்கும் ஒரு நிலையைக் குறிக்கும். まどがあけてある (mado ga akete aru — ஜன்னல் [வேண்டுமென்றே] திறந்தே வைக்கப்பட்டுள்ளது) <button class=\"speak-btn\" data-speak=\"まどがあけてある\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>～ている</strong>-உடன் ஒப்பிடுக: まどがあいている (mado ga aiteiru — ஜன்னல் திறந்திருக்கிறது) — இது ஒரு எளிய நிலையைக் காட்டும், யார் அதை அப்படி வைத்தார்கள் அல்லது ஏன் என்பதில் கவனம் இல்லை.</li>\n                                        <li><strong>～てみる:</strong> என்ன நடக்கும் எனப் பார்க்க ஏதேனும் ஒன்றை \"முயற்சித்துப் பார்த்தல்\". たべてみる (tabete miru — [அதைச்] சாப்பிட்டுப் பார்)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a>-இல் சரியான て-வடிவ நீட்டிப்பைத் தேர்ந்தெடுங்கள், பிறகு <a href=\"#\" data-goto-tab=\"builder\">வாக்கிய கட்டமைப்பாளர்</a>-இல் அவற்றை உங்கள் சொந்த வாக்கியங்களில் பயன்படுத்துங்கள்.</p>\n                                </div>\n                            </div>","day-pane-21":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-crown\" style=\"color: var(--accent-pink);\"></i> N3·8: கெய்கோ I (Keigo) — மரியாதைச் சொல் மற்றும் பணிவுச் சொல் வினைகள்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p><strong>敬語 (keigo)</strong> என்பது ஜப்பானின் மரியாதைப் பேச்சு முறையாகும். <strong>尊敬語</strong> (மரியாதைச் சொல் / honorific) மற்றவரின் செயலை உயர்த்திக் காட்டும்; <strong>謙譲語</strong> (பணிவுச் சொல் / humble) கேட்பவருக்கு மரியாதை காட்டும் விதமாக உங்கள் சொந்தச் செயலைத் தாழ்த்திக் கூறும். மிகவும் பொதுவாகப் பயன்படுத்தப்படும் சில வினைச்சொற்களுக்கு முற்றிலும் ஒழுங்கற்ற கெய்கோ வடிவங்கள் உள்ளன — இவற்றை முதலில் கற்றுக்கொள்ளுங்கள்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. சாதாரண வடிவம் → மரியாதைச் சொல் → பணிவுச் சொல்</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>சாதாரணம்</th><th>மரியாதைச் சொல் (尊敬語)</th><th>பணிவுச் சொல் (謙譲語)</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>いる (iru — இருப்பது)</td><td><span class=\"ja-word\">いらっしゃる</span> (irassharu)</td><td><span class=\"ja-word\">おる</span> (oru)</td></tr>\n                                            <tr><td>いく／くる (iku/kuru — செல்வது/வருவது)</td><td><span class=\"ja-word\">いらっしゃる</span> (irassharu)</td><td><span class=\"ja-word\">まいる</span> (mairu)</td></tr>\n                                            <tr><td>いう (iu — சொல்வது)</td><td><span class=\"ja-word\">おっしゃる</span> (ossharu)</td><td><span class=\"ja-word\">もうす</span> (mousu)</td></tr>\n                                            <tr><td>たべる／のむ (taberu/nomu — சாப்பிடுவது/குடிப்பது)</td><td><span class=\"ja-word\">めしあがる</span> (meshiagaru)</td><td><span class=\"ja-word\">いただく</span> (itadaku)</td></tr>\n                                            <tr><td>する (suru — செய்வது)</td><td><span class=\"ja-word\">なさる</span> (nasaru)</td><td><span class=\"ja-word\">いたす</span> (itasu)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"font-size:0.85rem;color:var(--text-muted);\">மரியாதைச் சொல் வினைகள் <strong>மற்றவர்களின்</strong> செயல்களை (ஆசிரியர், வாடிக்கையாளர், உங்கள் மேலாளர் போன்றோர்) உயர்த்திக் காட்டும்; பணிவுச் சொல் வினைகள் கேட்பவருக்கு மரியாதை காட்ட <strong>உங்கள் சொந்த</strong> செயல்களைத் தாழ்த்திக் கூறும். இந்த இரண்டையும் ஒரே நபருக்காகக் கலந்து பயன்படுத்த வேண்டாம்.</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ます-வடிவத்தில் கவனம் தேவை — நான்கு ஒழுங்கற்ற வினைகள்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>いらっしゃる, おっしゃる, なさる, மற்றும் くださる ஆகிய நான்கும் ～ります அல்ல, ～います எனும் வடிவை எடுத்துக்கொள்கின்றன: いらっしゃる → <span class=\"ja-word\">いらっしゃいます</span> (irassharu → irasshaimasu), おっしゃる → <span class=\"ja-word\">おっしゃいます</span> (ossharu → osshaimasu).</li>\n                                        <li>せんせいはいついらっしゃいますか (sensei wa itsu irasshaimasu ka — ஆசிரியர் எப்போது வருவார்?) <button class=\"speak-btn\" data-speak=\"せんせいはいついらっしゃいますか\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>しゃちょうはなんとおっしゃいましたか (shachou wa nan to osshaimashita ka — தலைவர் என்ன சொன்னார்?) <button class=\"speak-btn\" data-speak=\"しゃちょうはなんとおっしゃいましたか\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. நடைமுறையில் பணிவுச் சொல் — தன்னைத் தாழ்த்திக் கூறுதல்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>たなかともうします (Tanaka to moushimasu — என்னை தானகா என்று அழைக்கிறார்கள் [பணிவான சுய அறிமுகம்]) <button class=\"speak-btn\" data-speak=\"たなかともうします\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>わたしはあしたまいります (watashi wa ashita mairimasu — நான் நாளை செல்வேன்/வருவேன் [பணிவுச் சொல்])</li>\n                                        <li>どうぞめしあがってください (douzo meshiagatte kudasai — தயவுசெய்து சாப்பிடுங்கள் [மரியாதைச் சொல், விருந்தினரிடம் சொல்லப்படுவது])</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">க்வெஸ்ட் அரங்கம்</a>-இல் மரியாதைச் சொல் மற்றும் பணிவுச் சொல் ஜோடிகளைப் பொருத்துங்கள், பிறகு <a href=\"#\" data-goto-tab=\"flashcards\">ஃப்ளாஷ்கார்டுகள்</a> மூலம் முழு கெய்கோ அட்டவணையையும் மறுபரிசீலனை செய்யுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-22":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scroll\" style=\"color: var(--accent-pink);\"></i> N2·1: ～ものだ குடும்பம்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>もの (\"பொருள்/விஷயம்\") இங்கே மூன்று வெவ்வேறு முடிவுகளாக மாறுகிறது: <strong>ものだ</strong> ஒரு பொதுவான உண்மையை, ஏக்கமான நினைவை அல்லது மென்மையான கண்டிப்பை வெளிப்படுத்துகிறது; <strong>ものの</strong> ஒரு உண்மையை ஒப்புக்கொண்டபின் அதற்கு மாறான ஒன்றுக்குத் திரும்புகிறது; <strong>ものだから</strong> இப்போது நடந்ததை நியாயப்படுத்த ஒரு காரணத்தை முன்வைக்கிறது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ものだ — மூன்று பாவனைகள், ஒரே முடிவு</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>பயன்பாடு</th><th>விதி</th><th>உதாரணம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>பொதுவான உண்மை</td><td>சாதாரண வடிவம் + ものだ</td><td>ひとはだれでもしっぱいするものだ (hito wa dare demo shippai suru mono da — எல்லோரும் தவறு செய்வார்கள், அதுதான் இயல்பு) <button class=\"speak-btn\" data-speak=\"ひとはだれでもしっぱいするものだ\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>ஏக்கம் (கடந்தகால பழக்கம்)</td><td>た-வடிவம் + ものだ</td><td>こどものころ、よくこのかわでおよいだものだ (kodomo no koro, yoku kono kawa de oyoida mono da — நான் சிறுவனாக இருந்தபோது, இந்த ஆற்றில் அடிக்கடி நீச்சலடிப்பேன்) <button class=\"speak-btn\" data-speak=\"こどものころ、よくこのかわでおよいだものだ\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>மென்மையான கட்டளை (\"செய்ய வேண்டும்\")</td><td>சாதாரண வடிவம் + ものだ</td><td>あいさつはきちんとするものだ (aisatsu wa kichinto suru mono da — முறையாக வாழ்த்து சொல்ல வேண்டும்)</td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ものの — ஆனாலும், ஆனால் பிறகு...</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>சாதாரண வடிவம் (எந்தக் காலமும்) + ものの ஒரு உண்மையை ஒப்புக்கொண்டு, பின்பு எதிர்பாராத அல்லது ஏமாற்றமான முடிவைக் கூறுகிறது — けれども-ஐ விட இது முறையான/எழுத்து வடிவ மொழிக்கு நெருக்கமானது.</li>\n                                        <li>にほんごをさんねんべんきょうしたものの、まだうまくはなせない (nihongo o sannen benkyou shita mono no, mada umaku hanasenai — மூன்று வருடங்கள் ஜப்பானிய மொழி படித்திருந்தும், இன்னும் நன்றாகப் பேச முடியவில்லை) <button class=\"speak-btn\" data-speak=\"にほんごをさんねんべんきょうしたものの、まだうまくはなせない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>あたまではわかっているものの、なかなかじっこうできない (atama de wa wakatteiru mono no, nakanaka jikkou dekinai — தலையில் புரிந்திருந்தும், அதை நடைமுறையில் செயல்படுத்த முடியவில்லை)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ものだから — சாக்குப்போக்குக் காரணம்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>சாதாரண வடிவம் + ものだから ஒரு காரணத்தைத் தருகிறது, அதுவே ஒரு சாக்குப்போக்காகவும் அமைகிறது; பொதுவாக அதைத் தொடர்ந்து மன்னிப்போ விளக்கமோ வரும் — பேச்சுவழக்கில் அதிகம் காணப்படுகிறது.</li>\n                                        <li>でんしゃがおくれたものだから、ちこくしてしまいました (densha ga okureta mono da kara, chikoku shite shimaimashita — ரயில் தாமதமானதால், [அதனால்தான்] நான் தாமதமாகிவிட்டேன்) <button class=\"speak-btn\" data-speak=\"でんしゃがおくれたものだから、ちこくしてしまいました\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>பேச்சுவழக்கில் இது சுருக்கப்படும்: ものだから → もんだから (mono da kara → mon da kara).</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரீனா</a>-வில் மூன்று もの முடிவுகளையும் கண்டறியவும், பின்பு <a href=\"#\" data-goto-tab=\"flashcards\">ஃபிளாஷ்கார்டுகள்</a> மூலம் பயிற்சி செய்யவும்.</p>\n                                </div>\n                            </div>","day-pane-23":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scale-balanced\" style=\"color: var(--accent-pink);\"></i> N2·2: ～わけだ குடும்பம்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>わけ (\"காரணம்/சூழ்நிலை\") மூன்று N2 அடிப்படை அமைப்புகளை உருவாக்குகிறது. <strong>わけだ</strong> இயல்பான முடிவை எடுத்துரைக்கிறது — \"ஆச்சரியமில்லை, அதாவது...\" <strong>わけではない</strong> ஒரு பொதுவான கூற்றை மென்மையாக்கி \"அது அவசியமில்லை...\" எனக் காட்டுகிறது; <strong>わけにはいかない</strong> ஒரு சமூக அல்லது தார்மீகக் கடமை ஒரு செயலைத் தடை செய்வதைக் குறிக்கிறது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. わけだ — ஆச்சரியமில்லை / அதாவது</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>சாதாரண வடிவம் + わけだ, சற்றுமுன் கூறப்பட்டதிலிருந்து அல்லது கவனிக்கப்பட்டதிலிருந்து தர்க்கரீதியாகப் பின்தொடரும் ஒரு முடிவைக் கூறுகிறது.</li>\n                                        <li>さんねんかんにほんにすんでいた。だから、にほんごがじょうずなわけだ (san-nen kan nihon ni sundeita. dakara, nihongo ga jouzu na wake da — மூன்று வருடங்கள் ஜப்பானில் வாழ்ந்திருக்கிறார்கள். அதனால்தான் அவர்களின் ஜப்பானிய மொழி திறமையாக இருக்கிறது) <button class=\"speak-btn\" data-speak=\"さんねんかんにほんにすんでいた。だから、にほんごがじょうずなわけだ\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>どうりでさむいわけだ、ゆきがふっている (douri de samui wake da, yuki ga futteiru — ஆச்சரியமில்லை, குளிராக இருக்கிறது, பனி பெய்கிறது) <button class=\"speak-btn\" data-speak=\"どうりでさむいわけだ、ゆきがふっている\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. わけではない — அது அப்படி இல்லை... / அவசியமில்லை</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>சாதாரண வடிவம் + わけではない ஒரு அனுமானத்தை முழுவதுமாக மறுக்காமல் பகுதியளவு மறுக்கிறது.</li>\n                                        <li>きらいなわけではないが、あまりたべたくない (kirai na wake de wa nai ga, amari tabetakunai — எனக்கு அது பிடிக்கவில்லை என்பதல்ல, ஆனால் அதிகம் சாப்பிட விரும்பவில்லை) <button class=\"speak-btn\" data-speak=\"きらいなわけではないが、あまりたべたくない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>ぜんぶわかったわけではない (zenbu wakatta wake de wa nai — எல்லாம் புரிந்துகொண்டேன் என்பதல்ல)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. わけにはいかない — முடியாது / அப்படியே செய்ய முடியாது</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>அகராதி வடிவம் + わけにはいかない: நீங்கள் செய்ய விரும்பினாலும், ஒரு சமூக, தார்மீக அல்லது சூழ்நிலைக் கடமை அந்தச் செயலைத் தடுக்கிறது.</li>\n                                        <li>あしたはしけんがあるから、きょうはあそぶわけにはいかない (ashita wa shiken ga aru kara, kyou wa asobu wake ni wa ikanai — நாளை எனக்குத் தேர்வு இருக்கிறது, அதனால் இன்று போய் விளையாட முடியாது) <button class=\"speak-btn\" data-speak=\"あしたはしけんがあるから、きょうはあそぶわけにはいかない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>எதிர்மறை வடிவமான ないわけにはいかない (\"செய்யாமல் இருக்க முடியாது\"), அடுத்த பாடத்தில் தனியாகக் கையாளப்படும்.</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரீனாவில்</a> わけだ-ஐ わけではない-இலிருந்து பிரித்தறியவும், பின்பு <a href=\"#\" data-goto-tab=\"bridge\">கிராமர் பிரிட்ஜில்</a> உங்கள் குறிப்புகளைச் சரிபார்க்கவும்.</p>\n                                </div>\n                            </div>","day-pane-24":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-hand-fist\" style=\"color: var(--accent-pink);\"></i> N2·3: கடமை மற்றும் கட்டாயம்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>「வேறு வழியில்லை」 என்று சொல்வதற்கான மூன்று கனமான வழிகள். <strong>～ざるを得ない</strong> உங்கள் கட்டுப்பாட்டைத் தாண்டிய சூழ்நிலைகளால் ஏற்படும் மனமில்லாத கட்டாயத்தைக் குறிக்கிறது. <strong>～ずにはいられない</strong> அடக்கிவைக்க முடியாத அளவுக்குக் கடுமையான உணர்ச்சிபூர்வமான உந்துதலைக் குறிக்கிறது. <strong>～ないわけにはいかない</strong> தவிர்க்க முடியாத ஒரு சமூக அல்லது தார்மீகக் கடமையைக் குறிக்கிறது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ざるを得ない அமைப்பு (மற்றும் ～ずにはいられない)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>குழு</th><th>விதி</th><th>உதாரணம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>う-verbs</td><td>ない-வடிவ வேர்ச்சொல் + ざるを得ない</td><td>のむ → のまない → <span class=\"ja-word\">のまざるをえない</span> (nomu → nomanai → nomazaru o enai — குடி → குடிக்காமல் வேறு வழியில்லை)</td></tr>\n                                            <tr><td>る-verbs</td><td>ない-வடிவ வேர்ச்சொல் + ざるを得ない</td><td>やめる → やめない → <span class=\"ja-word\">やめざるをえない</span> (yameru → yamenai → yamezaru o enai — விடுவது → விடாமல் வேறு வழியில்லை)</td></tr>\n                                            <tr><td>ஒழுங்கற்ற する</td><td>せざるを得ない, இது さざるを得ない அல்ல</td><td>する → <span class=\"ja-word\">せざるをえない</span> (suru → sezaru o enai)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">～ずにはいられない-ம் இதே முறையில் உருவாக்கப்படுகிறது — ざるを得ない-க்குப் பதிலாக ずにはいられない-ஐ பயன்படுத்தவும் (ஒழுங்கற்ற する → せずにはいられない, மேலே உள்ள அதே せ).</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ざるを得ない நடைமுறையில் — மனமில்லாத கட்டாயம்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>きゅうりょうがやすいので、やめざるをえない (kyuuryou ga yasui node, yamezaru o enai — சம்பளம் குறைவாக இருப்பதால், வேலையை விடாமல் வேறு வழியில்லை) <button class=\"speak-btn\" data-speak=\"きゅうりょうがやすいので、やめざるをえない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>じょうしにいわれたら、ざんぎょうせざるをえない (joushi ni iwaretara, zangyou sezaru o enai — மேலாளர் சொன்னால், கூடுதல் நேரம் வேலை செய்யாமல் வேறு வழியில்லை) <button class=\"speak-btn\" data-speak=\"じょうしにいわれたら、ざんぎょうせざるをえない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～ずにはいられない vs ～ないわけにはいかない</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>～ずにはいられない என்பது எதிர்க்க முடியாத அளவுக்குக் கடுமையான உணர்ச்சிபூர்வமான தூண்டுதலைக் குறிக்கும்: あのえいがをみると、なかずにはいられない (ano eiga o miru to, nakazu ni wa irarenai — அந்தத் திரைப்படத்தைப் பார்க்கும்போது, அழாமல் இருக்க முடியாது) <button class=\"speak-btn\" data-speak=\"あのえいがをみると、なかずにはいられない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>～ないわけにはいかない (ない-வடிவம் + わけにはいかない) என்பது தவிர்க்க முடியாத ஒரு சமூக அல்லது தார்மீகக் கடமையைக் குறிக்கும்: せんせいによばれたら、いかないわけにはいかない (sensei ni yobaretara, ikanai wake ni wa ikanai — ஆசிரியர் அழைத்தால், போகாமல் இருக்க முடியாது) <button class=\"speak-btn\" data-speak=\"せんせいによばれたら、いかないわけにはいかない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>வேறுபாடு: ざるを得ない \"நடைமுறையில் வேறு வழியில்லை\" என்பதைச் சுட்டிக்காட்டுகிறது; ないわけにはいかない \"கடமை என்னை கட்டாயப்படுத்துகிறது\" என்பதைச் சுட்டிக்காட்டுகிறது.</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரீனாவில்</a> மூன்று \"வேறு வழியில்லை\" அமைப்புகளையும் பயிற்சி செய்யவும், பின்பு <a href=\"#\" data-goto-tab=\"builder\">செண்டன்ஸ் பில்டர்</a> மூலம் உங்கள் சொந்த வாக்கியங்களை உருவாக்கவும்.</p>\n                                </div>\n                            </div>","day-pane-25":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scale-unbalanced\" style=\"color: var(--accent-pink);\"></i> N2·4: முரண்பாட்டுக் கூற்றுகள்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>எதிர்பார்ப்புக்கும் நிதர்சனத்துக்கும் இடையேயான முரண்பாட்டைக் காட்டும் மூன்று வழிகள். <strong>にもかかわらず</strong> \"இருந்தும்/போதிலும்\" எனும் மிகவும் வலிமையான வெளிப்பாடு. <strong>にしては</strong> ஒரு வகைப்பாடு பொதுவாக எதிர்பார்க்கும் தரத்திற்கு எதிராக ஒன்றை மதிப்பிடுகிறது. <strong>わりに(は)</strong> கொடுக்கப்பட்ட நிபந்தனைக்கு ஏற்ப முடிவு இல்லாமல் இருப்பதைக் கூறுகிறது — にしては-ஐ விட மென்மையான, நடுநிலையான சொல்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. にもかかわらず — இருந்தும் / போதிலும்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>சாதாரண வடிவம் / பெயர்ச்சொல் + にもかかわらず ஒரு உண்மையைக் கூறி, பிறகு ஆச்சரியமான அல்லது முரணான ஒரு முடிவைத் தருகிறது — முறையான, எழுத்து வடிவத்தில் அதிகம் பயன்படுத்தப்படும் சொல்.</li>\n                                        <li>あめにもかかわらず、おおぜいのひとがきた (ame ni mo kakawarazu, oozei no hito ga kita — மழை பெய்தும், நிறைய பேர் வந்தார்கள்) <button class=\"speak-btn\" data-speak=\"あめにもかかわらず、おおぜいのひとがきた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>いっしょうけんめいべんきょうしたにもかかわらず、しけんにおちてしまった (isshoukenmei benkyou shita ni mo kakawarazu, shiken ni ochite shimatta — கடுமையாகப் படித்திருந்தும், தேர்வில் தோற்றுவிட்டேன்) <button class=\"speak-btn\" data-speak=\"いっしょうけんめいべんきょうしたにもかかわらず、しけんにおちてしまった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. にしては — ...க்கு / கருத்தில்கொண்டால் (ஆச்சரியத் தொனி)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>பெயர்ச்சொல் / சாதாரண வடிவம் + にしては ஒரு நபரையோ பொருளையோ, அது சேர்ந்த வகைப்பாடு குறிக்கும் தரத்திற்கு எதிராக மதிப்பிடுகிறது: \"~-க்கு இது ஆச்சரியமானது.\"</li>\n                                        <li>こどもにしては、よくかんじをしっている (kodomo ni shite wa, yoku kanji o shitteiru — ஒரு குழந்தைக்கு, நிறைய கஞ்சி தெரிந்திருக்கிறது) <button class=\"speak-btn\" data-speak=\"こどもにしては、よくかんじをしっている\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>はじめてにしては、じょうずにできた (hajimete ni shite wa, jouzu ni dekita — முதல் முயற்சிக்கு, நன்றாக முடிந்தது)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. わりに(は) — ஒப்பீட்டளவில் / கருத்தில்கொண்டால் (நடுநிலைத் தொனி)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>பெயர்ச்சொல் (+の) / な-உரிச்சொல் (+な) / சாதாரண வடிவம் + わりに(は): நிபந்தனை பொதுவாக எதிர்பார்க்கும் முடிவுக்கும் உண்மையான முடிவுக்கும் பொருத்தமில்லை — にしては போலல்லாமல், இதற்கு ஒரு உள்ளார்ந்த \"தரநிலை\" தேவையில்லை.</li>\n                                        <li>このみせはねだんがたかいわりには、あまりおいしくない (kono mise wa nedan ga takai wari ni wa, amari oishikunai — இந்த உணவகத்தின் விலை அதிகம் என்பதைக் கருத்தில்கொண்டால், அது அவ்வளவு சுவையாக இல்லை)</li>\n                                        <li>ねんれいのわりに、わかくみえる (nenrei no wari ni, wakaku mieru — வயதைக் கருத்தில்கொண்டால், இளமையாகத் தெரிகிறார்கள்) <button class=\"speak-btn\" data-speak=\"ねんれいのわりに、わかくみえる\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரீனாவில்</a> மூன்று முரண்பாடுகளையும் வேறுபடுத்திப் பாருங்கள், பின்பு <a href=\"#\" data-goto-tab=\"bridge\">கிராமர் பிரிட்ஜில்</a> நுணுக்கமான குறிப்புகளை மறுபரிசீலனை செய்யுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-26":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-wave-square\" style=\"color: var(--accent-pink);\"></i> N2·5: போக்குகள்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>ஒரு நிலையை முழுமையாக அடையாமல் அதை நோக்கி \"சாய்வதைக்\" குறிக்கும் மூன்று பின்னொட்டுகள். <strong>～がち</strong> மீண்டும் மீண்டும் நிகழும், பொதுவாக விரும்பத்தகாத ஒரு போக்கு. <strong>～気味</strong> (ぎみ) இப்போது நடக்கும் லேசான, பெரும்பாலும் உடல்சார்ந்த ஒரு போக்கு. <strong>～っぽい</strong> ஒரு பண்பையோ வகையையோ ஒத்திருப்பதைக் \"-ஆன தன்மை\" எனக் காட்டுகிறது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～がち — சாய்வுள்ள / சார்பான</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ます-வேர்ச்சொல் அல்லது பெயர்ச்சொல் + がち மீண்டும் மீண்டும் நிகழும், பொதுவாக விரும்பத்தகாத ஒரு போக்கைக் குறிக்கிறது.</li>\n                                        <li>かれはやくそくをわすれがちだ (kare wa yakusoku o wasuregachi da — அவன் தன் வாக்குறுதிகளை மறந்துவிடும் போக்குடையவன்) <button class=\"speak-btn\" data-speak=\"かれはやくそくをわすれがちだ\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>このごろ、くもりがちのてんきがつづいている (kono goro, kumorigachi no tenki ga tsuzuiteiru — இந்த நாட்களில், மேகமூட்டமான வானிலை தொடர்கிறது)</li>\n                                        <li>பொதுவான தொடர்: びょうきがち (byoukigachi — அடிக்கடி நோய்வாய்ப்படும் தன்மையுடையவர்).</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～気味 (ぎみ) — லேசான உணர்வு / கொஞ்சம்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ます-வேர்ச்சொல் அல்லது பெயர்ச்சொல் + 気味: தற்போது இருக்கும் லேசான போக்கு அல்லது உணர்வு, がち-ஐ விட மென்மையானது, உடல்/மனம் சார்ந்தது.</li>\n                                        <li>さいきん、つかれぎみだ (saikin, tsukaregimi da — சமீபகாலமாக, கொஞ்சம் சோர்வாக இருக்கிறேன்) <button class=\"speak-btn\" data-speak=\"さいきん、つかれぎみだ\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>かぜぎみなので、きょうははやくねます (kazegimi na node, kyou wa hayaku nemasu — கொஞ்சம் சளிபிடித்தது போல் இருப்பதால், இன்று சீக்கிரம் தூங்குகிறேன்)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～っぽい — ...போன்ற / ...ஆகத் தெரிகிற/நடக்கிற</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>い-உரிச்சொல் வேர்ச்சொல் / பெயர்ச்சொல் / ます-வேர்ச்சொல் + っぽい ஒரு பண்பின் தோற்றத்தைக் காட்டுகிறது, பெரும்பாலும் லேசான எதிர்மறை அல்லது சாதாரணத் தொனியுடன்.</li>\n                                        <li>わすれっぽいひとですね (wasureppoi hito desu ne — நீங்கள் மறதி அதிகமுள்ளவர் போலிருக்கிறது, இல்லையா) <button class=\"speak-btn\" data-speak=\"わすれっぽいひとですね\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>かのじょはこどもっぽい (kanojo wa kodomoppoi — அவள் குழந்தைத்தனமானவள்)</li>\n                                        <li>みずっぽいスープ (mizuppoi suupu — நீர்த்த சூப்)</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"flashcards\">ஃபிளாஷ்கார்டுகள்</a> மூலம் மூன்று போக்குகளையும் உங்களைச் சோதித்துக்கொள்ளுங்கள், பின்பு <a href=\"#\" data-goto-tab=\"builder\">செண்டன்ஸ் பில்டரில்</a> உங்கள் சொந்த வாக்கியங்களில் அவற்றைப் பயன்படுத்துங்கள்.</p>\n                                </div>\n                            </div>","day-pane-27":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-arrow-trend-up\" style=\"color: var(--accent-pink);\"></i> N2·6: தொடர்புடைய மாற்றம்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>இந்த மூன்றும் ஒன்றுடனொன்று மாறும் இரண்டு விஷயங்களை விவரிக்கின்றன — \"X மாறும்போது, Y மாறும்\" — இவை ஒன்றுடன் ஒன்று மிகவும் ஒத்துப்போகின்றன. ஆனாலும் ஒவ்வொன்றும் வெவ்வேறு பக்கம் சாய்கிறது: <strong>につれて</strong> படிப்படியான, இயற்கையான மாற்றத்தைக் குறிக்கும்; <strong>に伴って</strong> ஒரு மாற்றம் இன்னொன்றை உருவாக்குவதை எடுத்துக்காட்டும்; மேலும் <strong>に従って</strong> ஒரு விதிக்கு \"ஏற்ப/இணங்க\" என்ற பொருளையும் தரலாம்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. மூன்றையும் உருவாக்கி ஒப்பிடுதல்</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>அமைப்பு</th><th>நுணுக்கம்</th><th>உதாரணம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>～につれて</td><td>படிப்படியான, இணையான இயற்கை மாற்றம்</td><td>としをとるにつれて、からだがよわくなる (toshi o toru ni tsurete, karada ga yowaku naru — வயதாகும்போது, உடல் பலவீனமடைகிறது) <button class=\"speak-btn\" data-speak=\"としをとるにつれて、からだがよわくなる\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>～に伴って</td><td>ஒரு மாற்றம் இன்னொன்றைக் கொண்டுவரும்/உடன் வரும், பெரும்பாலும் பெரிய அளவில்</td><td>じんこうのぞうかにともなって、じゅうたくぶそくがしんこくかしている (jinkou no zouka ni tomonatte, juutaku busoku ga shinkokuka shiteiru — மக்கள்தொகை அதிகரிப்புடன், வீட்டுவசதிப் பற்றாக்குறை மோசமடைந்து வருகிறது) <button class=\"speak-btn\" data-speak=\"じんこうのぞうかにともなって、じゅうたくぶそくがしんこくかしている\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>～に従って</td><td>ஒரு விதியை/வழிமுறையைப் பின்பற்றுதல், அல்லது படிப்படியான முன்னேற்றம்</td><td>きそくにしたがってこうどうしてください (kisoku ni shitagatte koudou shite kudasai — தயவுசெய்து விதிகளுக்கு ஏற்ப நடந்துகொள்ளுங்கள்) <button class=\"speak-btn\" data-speak=\"きそくにしたがってこうどうしてください\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                        </tbody>\n                                    </table>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. இவை எங்கு வேறுபடுகின்றன</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>முற்றிலும் படிப்படியான, இணையான மாற்றத்திற்கு, மூன்றும் பெரும்பாலும் ஒன்றுக்கொன்று மாற்றாகப் பயன்படுத்தப்படலாம்: ぶっかがあがるにつれて、せいかつがくるしくなる (bukka ga agaru ni tsurete, seikatsu ga kurushiku naru — விலைவாசி உயரும்போது, வாழ்க்கை கடினமாகிறது) — இங்கே に伴って அல்லது に従って-ஐயும் பொருள் பெரிதாக மாறாமல் பயன்படுத்தலாம்.</li>\n                                        <li>に伴って மட்டுமே, உடன் நிகழும் விளைவை விவரிக்கும் நிகழ்வுப் பெயர்ச்சொற்களுடன் இயல்பாக இணையும்: たいふうのせっきんにともなって、でんしゃがとまった (taifuu no sekkin ni tomonatte, densha ga tomatta — புயல் நெருங்கியதுடன், ரயில்கள் நின்றுவிட்டன) <button class=\"speak-btn\" data-speak=\"たいふうのせっきんにともなって、でんしゃがとまった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>に従って மட்டுமே, ஒரு விதி, கட்டளை அல்லது வழிமுறைக்கு \"ஏற்ப/இணங்க\" என்ற பொருளுக்கும் இயல்பாக விரிவடையும் — வெறும் படிப்படியான மாற்றத்திற்கு மட்டுமல்ல.</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரீனாவில்</a> சரியான தொடர்புடைய-மாற்ற அமைப்பைப் பொருத்துங்கள், பின்பு <a href=\"#\" data-goto-tab=\"bridge\">கிராமர் பிரிட்ஜில்</a> நுணுக்கமான குறிப்புகளை மறுபரிசீலனை செய்யுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-28":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-newspaper\" style=\"color: var(--accent-pink);\"></i> N2·7: எழுத்து வடிவ ஜப்பானிய மொழி\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>முறையான எழுத்து வடிவ ஜப்பானிய மொழி — செய்தித்தாள்கள், அறிக்கைகள், கல்விசார் கட்டுரைகள் — பணிவான です／ます பாணிக்குப் பதிலாக சாதாரண・である பாணியைப் பயன்படுத்துகிறது, மேலும் சாதாரணப் பேச்சில் அரிதாகவே கேட்கும் சில இலக்கண அமைப்புகளை நம்பியிருக்கிறது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. である பாணி — எழுத்து-அறிக்கை மொழிநடை</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>சாதாரண/பணிவான முடிவு</th><th>எழுத்து வடிவ (である) சமானம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>だ／です</td><td>である — これはもんだいである (kore wa mondai de aru — இது ஒரு பிரச்சனை) <button class=\"speak-btn\" data-speak=\"これはもんだいである\"><i class=\"fa-solid fa-volume-high\"></i></button></td></tr>\n                                            <tr><td>だった</td><td>であった</td></tr>\n                                            <tr><td>ではない／じゃない</td><td>ではない (மாறாதது — உறுதிமொழி இணைப்புவினை மட்டுமே மாறுகிறது)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">である பாணியும் சாதாரண வடிவ வினைச்சொற்களையும் உரிச்சொற்களையும் (たべる、たかい) பயன்படுத்துகிறது — இணைப்புவினை மட்டுமே மாறுகிறது. ஒரே எழுத்துப் பகுதிக்குள் ですます-ஐயும் である-ஐயும் கலக்கக்கூடாது.</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. により மற்றும் における — காரணமும் சூழலும், முறையான வடிவில்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>～により (によって／で-க்கான முறையான வடிவம்) ஒரு காரணத்தையோ, வழிமுறையையோ, வழியையோ குறிக்கிறது: たいふうにより、おおくのいえがこわれた (taifuu ni yori, ooku no ie ga kowareta — புயலின் காரணமாக, பல வீடுகள் அழிந்தன) <button class=\"speak-btn\" data-speak=\"たいふうにより、おおくのいえがこわれた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>～における (での／においての-க்கான முறையான வடிவம்) ஒரு கூற்று பொருந்தும் நேரத்தையோ, இடத்தையோ, துறையையோ குறிப்பிட்டு, ஒரு பெயர்ச்சொல்லுடன் நேரடியாக இணைகிறது: にほんにおけるしょうしかもんだい (nihon ni okeru shoushika mondai — ஜப்பானில் பிறப்பு விகிதம் குறையும் பிரச்சனை)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. をめぐって — பற்றி / குறித்து (ஒரு சர்ச்சையில்)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>பெயர்ச்சொல் + をめぐって \"பற்றி/குறித்து\" எனும் பொருளைத் தருகிறது, ஒரு சர்ச்சைக்குரிய தலைப்பைப் பற்றி — கிட்டத்தட்ட எப்போதும் ஒரு தகராறு, விவாதம் அல்லது வாதத்துடன் இணைந்து வரும்.</li>\n                                        <li>あたらしいほうりつをめぐって、はげしいぎろんがつづいている (atarashii houritsu o megutte, hageshii giron ga tsuzuiteiru — புதிய சட்டத்தைக் குறித்து கடுமையான விவாதம் தொடர்கிறது) <button class=\"speak-btn\" data-speak=\"あたらしいほうりつをめぐって、はげしいぎろんがつづいている\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"bridge\">கிராமர் பிரிட்ஜில்</a> எழுத்து-பாணி இலக்கணத்தைக் கண்டறியவும், பின்பு <a href=\"#\" data-goto-tab=\"flashcards\">ஃபிளாஷ்கார்டுகள்</a> மூலம் உங்களைச் சோதித்துக்கொள்ளவும்.</p>\n                                </div>\n                            </div>","day-pane-29":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-briefcase\" style=\"color: var(--accent-pink);\"></i> N2·8: Keigo II — வணிக மொழிநடை\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>வணிக கெய்கோ, N3-இல் கற்ற மரியாதைச்சொல் / பணிவுச்சொல் அடிப்படைகளின் மீது ஒரு கூடுதல் விதியைச் சேர்க்கிறது: <strong>内・外 (uchi・soto)</strong>. வெளியாரான ஒரு வாடிக்கையாளரிடம் பேசும்போது, உங்கள் சொந்த மேலாளரும் சக ஊழியர்களும் \"உங்கள் தரப்பு\" (内) ஆகிவிடுவார்கள் — அவர்களின் செயல்களை எப்போதும் பணிவுச்சொல் மூலம் விவரிக்கவும், மரியாதைச்சொல் மூலம் அல்ல, அதே மேலாளரிடம் நேரடியாகப் பேசும்போது நீங்கள் மரியாதைச்சொல் பயன்படுத்தினாலும் கூட.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. 内 (uchi) vs 外 (soto) — யாருக்கு மரியாதை தரப்படுகிறது</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>நிறுவனத்திற்குள் ஒரு சக ஊழியரிடம்: ぶちょうはもういらっしゃいました (buchou wa mou irasshaimashita — மேலாளர் ஏற்கனவே வந்துவிட்டார்) — இது மரியாதைச்சொல், ஏனெனில் இங்கு அனைவரும் \"உள்ளே\" இருக்கிறார்கள். <button class=\"speak-btn\" data-speak=\"ぶちょうはもういらっしゃいました\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>வெளியாரான வாடிக்கையாளரிடம், அதே மேலாளரைப் பற்றி: ぶちょうはもうまいりました (buchou wa mou mairimashita — மேலாளர் ஏற்கனவே வந்துவிட்டார்) — இது பணிவுச்சொல், ஏனெனில் வாடிக்கையாளரின் பார்வையில் உங்கள் மேலாளர் இப்போது \"உங்கள் தரப்பு\"; நிறுவனத்திற்குள் இருக்கும் பதவி இனி முக்கியமில்லை. <button class=\"speak-btn\" data-speak=\"ぶちょうはもうまいりました\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>இந்த மாற்றம் கற்பவர்களை எந்த ஒரு வினைச்சொல் வடிவத்தையும் விட அதிகமாகக் குழப்புகிறது — இந்த விதி பேசப்படும் நபரைப் பற்றியது அல்ல, கேட்பவரைப் பற்றியது.</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ございます, おる, まいる — வணிக-முறையான தொகுப்பு</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>です → でございます: こちらがしりょうでございます (kochira ga shiryou de gozaimasu — இதோ ஆவணம்)</li>\n                                        <li>ある → ございます: おてあらいはあちらにございます (otearai wa achira ni gozaimasu — கழிவறை அங்கே இருக்கிறது)</li>\n                                        <li>いる → おる (பணிவுச்சொல், சொந்தத் தரப்பு): たなかはただいまがいしゅつしております (Tanaka wa tadaima gaishutsu shite orimasu — தனகா தற்போது அலுவலகத்திற்கு வெளியே இருக்கிறார்)</li>\n                                        <li>いく／くる → まいる (பணிவுச்சொல், சொந்தத் தரப்பு): すぐにまいります (sugu ni mairimasu — உடனே வருகிறேன்)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. お／ご + வேர்ச்சொல் + します — \"நான் உங்களுக்காக X செய்கிறேன்\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>お + வினைச்சொல்லின் ます-வேர்ச்சொல் + します (அல்லது பல する-வினைச்சொற்களுக்கு ご + வினைப்பெயர்ச்சொல் + します) கேட்பவருக்காக ஏதாவது செய்வதாகப் பணிவுடன் தெரிவிக்கிறது. மரியாதைச்சொல்லான お, お-வில் தொடங்கும் வேர்ச்சொல்லுடன் இரட்டிப்பாவதைக் கவனியுங்கள்: おくる → おくり → <span class=\"ja-word\">おおくりします</span> (okuru → okuri → o okuri shimasu — நான் அதை உங்களுக்கு அனுப்புகிறேன்), おくりします அல்ல.</li>\n                                        <li>ごれんらくします (go renraku shimasu — நான் உங்களைத் தொடர்பு கொள்கிறேன்) <button class=\"speak-btn\" data-speak=\"ごれんらくします\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>தொலைபேசி/மின்னஞ்சல் தொடக்க & முடிவு வாக்கியங்கள்: いつもおせわになっております (itsumo osewa ni natte orimasu — எப்போதும் உங்கள் ஆதரவுக்கு நன்றி); よろしくおねがいいたします (yoroshiku onegai itashimasu — முன்கூட்டியே நன்றி) <button class=\"speak-btn\" data-speak=\"いつもおせわになっております。よろしくおねがいいたします\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p><a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரீனாவில்</a> uchi/soto மாற்றத்தைப் பயிற்சி செய்யுங்கள், <a href=\"#\" data-goto-tab=\"builder\">செண்டன்ஸ் பில்டரில்</a> உங்கள் சொந்த வணிக சொற்றொடர்களை உருவாக்குங்கள், பின்பு <a href=\"#\" data-goto-tab=\"bridge\">கிராமர் பிரிட்ஜில்</a> முழுத் தொகுப்பையும் மறுபரிசீலனை செய்யுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-30":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scroll\" style=\"color: var(--accent-pink);\"></i> N1·1: இலக்கிய எதிர்மறைகள் — ～んがため, ～ずして, ～べからず\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>N1 பாடங்களில் இன்று நிலைத்தொடர்கள், பழமொழிகள், முறையான எழுத்துகளில் மட்டுமே எஞ்சியுள்ள பாரம்பரிய இலக்கணம் அதிகம் இடம்பெறுகிறது. இந்த மூன்று வடிவங்களும் பாரம்பரிய ஜப்பானிய மொழியின் எதிர்மறைச் சொற்கள் அல்லது துணைவினைகளிலிருந்து தோன்றியவை — இவற்றை அடையாளம் கண்டால் குறிக்கோள் வாக்கியங்கள், அறிவிப்புப் பலகைகள், இலக்கியப் பத்திகள் புரிந்துவிடும்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～んがため(に) — \"செய்வதற்காக\" (பழங்கால நோக்கம் தெரிவிக்கும் வடிவம்)</div>\n                                    <table class=\"grammar-table\">\n                                        <thead><tr><th>வடிவம்</th><th>விதி</th><th>உதாரணம்</th></tr></thead>\n                                        <tbody>\n                                            <tr><td>சாதாரண வினைச்சொற்கள்</td><td>ない-வடிவத்தில் ない-ஐ நீக்கிவிட்டு + んがために சேர்க்கவும்</td><td>生きる → 生きない → <span class=\"ja-word\">生きんがために</span> (ikiru → ikinai → ikin ga tame ni — வாழ்வதற்காக)</td></tr>\n                                            <tr><td>する (ஒழுங்கற்றது)</td><td>せんがために ஆகும், ஒருபோதும் しんがために அல்ல</td><td>合格する → <span class=\"ja-word\">合格せんがために</span> (goukaku suru → goukaku sen ga tame ni — [தேர்வில்] தேர்ச்சி பெறுவதற்காக)</td></tr>\n                                        </tbody>\n                                    </table>\n                                    <p style=\"margin-top:8px;font-size:0.85rem;color:var(--text-muted);\">பிரபலமான வரி: 人は生きんがために食う (hito wa ikin ga tame ni kuu — மனிதன் வாழ்வதற்காகவே உண்கிறான்) — வழக்கமான \"உண்பதற்காக வாழ்தல்\" என்பதற்கு நேர் எதிரானது.</p>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ずして — \"~ செய்யாமலேயே\" (முறையான ～ないで)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ない-வடிவத்தில் ない-ஐ நீக்கிவிட்டு + ずして சேர்க்கவும் — する, せずして ஆகிறது, ஒருபோதும் しずして அல்ல.</li>\n                                        <li>努力せずして成功はあり得ない (doryoku sezu shite seikou wa arienai — முயற்சியின்றி வெற்றி சாத்தியமில்லை) <button class=\"speak-btn\" data-speak=\"努力せずして成功はあり得ない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>\"～ずして何であろうか\" (sezu shite nan de arou ka — இது இல்லையெனில் வேறு என்னவாக இருக்கும்?) எனும் அமைப்பில் அமையும் சொல்லாட்சி வினாக்களில் பொதுவாகக் காணப்படும் — மாற்று சாத்தியத்தை மறுப்பதன் மூலம் ஒன்றை வலியுறுத்தி உறுதிசெய்யும் வடிவம்.</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～べからず — \"செய்யக்கூடாது\" (முறையான தடை)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>அகராதி வடிவம் + べからず — べし (வேண்டும்/தகும்) என்பதன் எதிர்மறை வடிவம்; する, すべからず ஆகிறது, இதுவே பொதுவாகக் காணப்படும் ஒரே ஒழுங்கற்ற விதிவிலக்கு.</li>\n                                        <li>芝生に入るべからず (shibafu ni hairu bekarazu — புல்வெளிக்குள் நுழையக்கூடாது) <button class=\"speak-btn\" data-speak=\"芝生に入るべからず\"><i class=\"fa-solid fa-volume-high\"></i></button> — பழைய அறிவிப்புப் பலகைகளில் காணப்படும் பாரம்பரியச் சொற்றொடர்.</li>\n                                        <li>இன்று பொதுவாக 立入禁止 எனும் எளிய அறிவிப்பே அதிகம் பயன்படுத்தப்படுகிறது, ஆனாலும் べからず வரலாற்றுப் பலகைகளிலும், குறிக்கோள் வாக்கியங்களிலும், முறையான எழுத்திலும் ～べきではない-ஐ விட வலுவான, இலக்கியத் தன்மை கொண்ட மாற்றாக இன்றும் காணப்படுகிறது.</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>இந்தப் பழங்கால எதிர்மறை வடிவங்களை <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் கண்டறியுங்கள், பிறகு அவற்றுக்குப் பின்னால் உள்ள பாரம்பரிய துணைவினைகளை <a href=\"#\" data-goto-tab=\"bridge\">மும்மொழி பாலம்</a>-இல் சரிபார்க்கவும்.</p>\n                                </div>\n                            </div>","day-pane-31":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-scale-unbalanced\" style=\"color: var(--accent-pink);\"></i> N1·2: விட்டுக்கொடுப்பு நுணுக்கங்கள் — ～ものを, ～ながら(も), ～といえども\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>விட்டுக்கொடுப்பு இலக்கணம் ஒரு உண்மையை ஒப்புக்கொண்டே, அதற்கு முரணாகத் தோன்றும் மற்றொரு கருத்தை உறுதிபடக் கூறும் — \"X ஆனாலும் Y.\" இந்த மூன்று வடிவங்களும் வெவ்வேறு உணர்வுகளைச் சேர்க்கின்றன: வருத்தம், அமைதியான முரண்பாடு, அல்லது முறையான வாதம்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ものを — வருத்தம்: \"இப்படி இருந்திருந்தால்...\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>நடந்திருக்க வேண்டியதை விவரிக்கும் சாதாரண வடிவ வாக்கியத்துடன் இணைகிறது — நிதர்சனம் வேறுவிதமாக நடந்ததால், பேசுபவரின் ஏமாற்றம் அல்லது வருத்தத்தை முடிவுறாமல் விட்டுவிடும்.</li>\n                                        <li>すぐに謝ればいいものを、彼は意地を張った (sugu ni ayamareba ii mono o, kare wa iji o hatta — உடனே மன்னிப்புக் கேட்டிருந்தால் போதுமே, ஆனால் அவன் பிடிவாதமாக இருந்தான்) <button class=\"speak-btn\" data-speak=\"すぐに謝ればいいものを、彼は意地を張った\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>பெரும்பாலும் ものを-க்குப் பின் வரும் வாக்கியம் முழுவதுமாக விடப்பட்டு, வருத்தம் மறைமுகமாகவே தெரிவிக்கப்படும்: 早く言ってくれればよかったものを…(hayaku itte kurereba yokatta mono o… — நீ இதை முன்னரே சொல்லியிருந்தால் நன்றாக இருந்திருக்குமே…)</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ながら(も) — \"ஆயினும் / போதிலும்\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>い-அடைமொழி / な-அடைமொழியின் அடிச்சொல் (な இல்லாமல், எ.கா. 残念ながら) / பெயர்ச்சொல் / வினைச்சொல்லின் ます-தண்டு + ながら(も) — N4-இல் கற்ற ஒரே நேரத்தில் நடக்கும் செயலைக் குறிக்கும் ながら-விலிருந்து வேறுபட்டது; இங்கே ஒரே எழுவாய்க்குள் ஏற்படும் முரண்பாட்டை ஒப்புக்கொள்கிறது.</li>\n                                        <li>狭いながらも、幸せな家庭を築いた (semai nagara mo, shiawase na katei o kizuita — சிறியதாக இருந்தபோதிலும், [அவர்கள்] மகிழ்ச்சியான குடும்பத்தை உருவாக்கினர்) <button class=\"speak-btn\" data-speak=\"狭いながらも、幸せな家庭を築いた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>知っていながら、彼は黙っていた (shitte inagara, kare wa damatte ita — தெரிந்திருந்தும், அவன் மவுனமாக இருந்தான்).</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～といえども — \"~ ஆனாலும் / ~ என்றபோதிலும்\" (முறையானது)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>பெயர்ச்சொல் / சாதாரண வடிவம் + といえども — ஒரு கருத்தை முழுமையாக ஒப்புக்கொண்டு, பிறகு அது எதையும் மாற்றாது எனக் கூறும்; கட்டுரைகள், உரைகள், சட்ட வகை வாதங்களில் பொதுவாகக் காணப்படும்.</li>\n                                        <li>子供といえども、責任は免れない (kodomo to iedomo, sekinin wa manugarenai — [அவன்] குழந்தையாக இருந்தாலும், பொறுப்பிலிருந்து தப்பிக்க முடியாது) <button class=\"speak-btn\" data-speak=\"子供といえども、責任は免れない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>プロといえども、失敗することはある (puro to iedomo, shippai suru koto wa aru — தொழில் வல்லுநர்களே ஆனாலும், சில நேரங்களில் தோல்வியடைவதும் உண்டு).</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>வருத்தத்தையும் விட்டுக்கொடுப்பையும் வேறுபடுத்திப் புரிந்துகொள்ள <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் முயற்சி செய்யுங்கள், பிறகு மூன்று வடிவங்களையும் <a href=\"#\" data-goto-tab=\"flashcards\">நினைவு அட்டைகள்</a> மூலம் பயிற்சி செய்யுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-32":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-bolt\" style=\"color: var(--accent-pink);\"></i> N1·3: உடனடித் தன்மை — ～なり, ～や否や, ～そばから\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>\"X நடந்த உடனேயே Y நடக்கிறது\" எனச் சொல்ல மூன்று வழிகள் — ஆனால் இவை ஒன்றுக்கொன்று மாற்றாகப் பயன்படுத்த முடியாது. なり மற்றும் や否や ஒரு எதிர்பாராத தருணத்தை விவரிக்கின்றன; そばから மீண்டும் மீண்டும் நிகழும் எரிச்சலூட்டும் சுழற்சியை விவரிக்கிறது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～なり — \"செய்த உடனேயே\" (ஒரே ஒரு எதிர்பாராத அடுத்த நிகழ்வு)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>அகராதி வடிவம் + なり — முதல் செயலுக்குப் பின் இரண்டாவது செயல் கிட்டத்தட்ட உடனடியாக நடக்கும், பெரும்பாலும் எதிர்பாராதது; இரு வாக்கியங்களின் எழுவாயும் பொதுவாக ஒரே நபராகவே இருக்கும்.</li>\n                                        <li>彼は帰宅するなり、部屋に閉じこもった (kare wa kitaku suru nari, heya ni tojikomotta — அவன் வீடு திரும்பிய உடனேயே, தன் அறையில் தன்னைப் பூட்டிக்கொண்டான்) <button class=\"speak-btn\" data-speak=\"彼は帰宅するなり、部屋に閉じこもった\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～や否や(やいなや) — \"...அந்த நொடியிலேயே\" (இலக்கியத் தன்மை கொண்டது)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>அகராதி வடிவம் + や否や — なり-ஐ விட இலக்கியத் தன்மை மிகுந்தது, கதை வடிவ எழுத்துகளில் பொதுவாகக் காணப்படும்; இரு வாக்கியங்களும் வெவ்வேறு எழுவாய்களைக் கொண்டிருக்கலாம்.</li>\n                                        <li>ベルが鳴るや否や、生徒たちは教室を飛び出した (beru ga naru ya ina ya, seitotachi wa kyoushitsu o tobidashita — மணி அடித்த அந்த நொடியிலேயே, மாணவர்கள் வகுப்பறையை விட்டு வேகமாக வெளியேறினர்) <button class=\"speak-btn\" data-speak=\"ベルが鳴るや否や、生徒たちは教室を飛び出した\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～そばから — \"செய்தவுடனேயே மீண்டும்...\" (திரும்பத் திரும்ப நிகழும் சுழற்சி)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>அகராதி வடிவம் / た-வடிவம் + そばから — なり மற்றும் や否やவிலிருந்து வேறுபட்டு, இது மீண்டும் மீண்டும் நிகழும், பெரும்பாலும் எரிச்சலூட்டும் ஒரு முறையை விவரிக்கிறது, இதில் இரண்டாவது செயல் தொடர்ந்து முதல் செயலைச் செயலிழக்கச் செய்கிறது.</li>\n                                        <li>片付けるそばから、子供が散らかす (katazukeru soba kara, kodomo ga chirakasu — நான் சுத்தம் செய்த உடனேயே, குழந்தைகள் மீண்டும் அசுத்தமாக்கி விடுகின்றனர்) <button class=\"speak-btn\" data-speak=\"片付けるそばから、子供が散らかす\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>習ったそばから忘れてしまう (naratta soba kara wasurete shimau — நான் கற்றுக்கொண்ட உடனேயே அதை மறந்துவிடுகிறேன்).</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>ஒரே முறை நிகழும் உடனடித் தன்மையையும் திரும்பத் திரும்ப நிகழும் சுழற்சியையும் <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் வேறுபடுத்திப் பாருங்கள், பிறகு <a href=\"#\" data-goto-tab=\"builder\">வாக்கிய அமைப்பான்</a>-இல் உங்கள் சொந்த なり மற்றும் そばから வாக்கியங்களை உருவாக்குங்கள்.</p>\n                                </div>\n                            </div>","day-pane-33":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-landmark\" style=\"color: var(--accent-pink);\"></i> N1·4: முறையான சூழல் — ～ともなると, ～とあって, ～に至って\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>ஒரு சிறப்பான நிலை, சந்தர்ப்பம், அல்லது உச்சக்கட்டம் தன்னைச் சுற்றியுள்ள அனைத்தையும் எப்படி மாற்றுகிறது என்பதை இந்த மூன்று வடிவங்களும் விவரிக்கின்றன — செய்தி அறிக்கைகளிலும் முறையான விமர்சனங்களிலும் பொதுவாகக் காணப்படும்.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～ともなると／～ともなれば — \"...என்ற நிலையை அடைந்துவிட்டால்\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>பெயர்ச்சொல் / வினைச்சொல்லின் அகராதி வடிவம் + ともなると(なれば) — ஒரு சிறப்பான நிலை, காலம், அல்லது அந்தஸ்து அடையப்படும்போது, அதைத் தொடர்ந்து இயல்பாகவே சில விளைவுகள் ஏற்படும்.</li>\n                                        <li>大企業の社長ともなると、責任は非常に重い (dai kigyou no shachou tomo naru to, sekinin wa hijou ni omoi — ஒரு பெரிய நிறுவனத்தின் தலைவராக ஆகிவிட்டால், பொறுப்பு மிகவும் கனமானதாக இருக்கும்) <button class=\"speak-btn\" data-speak=\"大企業の社長ともなると、責任は非常に重い\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>年末ともなれば、街は買い物客でにぎわう (nenmatsu tomo nareba, machi wa kaimonokyaku de nigiwau — ஆண்டு இறுதி வந்துவிட்டால், தெருக்கள் கடைக்கார வாடிக்கையாளர்களால் நிரம்பி வழியும்).</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～とあって — \"சிறப்பான ~ என்பதால்\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>பெயர்ச்சொல் / சாதாரண வடிவம் + とあって — ஒரு சிறப்பான சூழலைக் கூறி, அது ஏற்படுத்தும் இயல்பான எதிர்வினையை விவரிக்கும்; செய்தி பாணி எழுத்தில் பொதுவாகக் காணப்படும்.</li>\n                                        <li>連休とあって、高速道路はどこも渋滞している (renkyuu to atte, kousoku douro wa doko mo juutai shiteiru — நீண்ட விடுமுறை என்பதால், நெடுஞ்சாலைகள் எல்லா இடங்களிலும் நெரிசலாக உள்ளன) <button class=\"speak-btn\" data-speak=\"連休とあって、高速道路はどこも渋滞している\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～に至って(いたって) — \"...என்ற உச்சக்கட்டத்தை அடைந்தபோதுதான்\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>பெயர்ச்சொல் / வினைச்சொல்லின் அகராதி வடிவம் + に至って — ஒரு உச்சக்கட்டம் அடையப்பட்ட பிறகே ஒரு விஷயம் இறுதியாக உணரப்படுகிறது, முடிவெடுக்கப்படுகிறது, அல்லது நடவடிக்கை எடுக்கப்படுகிறது, பெரும்பாலும் \"தாமதமாகிவிட்டது\" என்ற பொருள் தொனிக்கும்.</li>\n                                        <li>手術が必要な状態に至って、彼はやっと病院へ行った (shujutsu ga hitsuyou na joutai ni itatte, kare wa yatto byouin e itta — அறுவை சிகிச்சை தேவைப்படும் நிலையை அடைந்தபோதுதான், அவன் இறுதியாக மருத்துவமனைக்குச் சென்றான்) <button class=\"speak-btn\" data-speak=\"手術が必要な状態に至って、彼はやっと病院へ行った\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>தொடர்புடையவை: ～に至っては என்பது ஒரு பெரிய குழுவிற்குள் ஒரு தீவிர உதாரணத்தைத் தனியாகக் குறிப்பிட்டுக் கருத்துச் சொல்லப் பயன்படும்; ～に至るまで என்றால் \"~ வரை முழுவதும்\" எனப் பொருள்.</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>இந்த முறையான-சூழல் வாக்கியங்களைப் படிக்கும் பயிற்சியை <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் செய்யுங்கள், பிறகு நுணுக்கங்களை <a href=\"#\" data-goto-tab=\"bridge\">மும்மொழி பாலம்</a>-இல் மறுபார்வையிடுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-34":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-fingerprint\" style=\"color: var(--accent-pink);\"></i> N1·5: குணநலன்களும் நிலைத்தொடர்களும் — ～きらいがある, ～ずにはおかない, ～を余儀なくされる\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>போக்குகளையும் நிர்ப்பந்தமான விளைவுகளையும் விவரிக்க மூன்று நிலைத்தொடர்கள் — ஒரு நபரின் எதிர்மறையான பழக்கம், தவிர்க்க முடியாத உணர்ச்சிபூர்வமான விளைவு, மற்றும் யாரும் தேர்ந்தெடுக்காத ஒரு சூழ்நிலை.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. ～きらいがある — \"~ செய்யும் போக்கு உண்டு\" (எதிர்மறையானது)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>வினைச்சொல்லின் அகராதி வடிவம் + きらいがある, அல்லது பெயர்ச்சொல் + の + きらいがある — ஒரு உள்ளார்ந்த, பொதுவாக விரும்பத்தகாத போக்கு அல்லது கெட்ட பழக்கத்தை விவரிக்கும், ஒரே தடவை நடக்கும் நிகழ்வைக் குறிக்காது.</li>\n                                        <li>彼は仕事を先延ばしにするきらいがある (kare wa shigoto o sakinobashi ni suru kirai ga aru — அவனுக்கு வேலையை தள்ளிப்போடும் போக்கு உண்டு) <button class=\"speak-btn\" data-speak=\"彼は仕事を先延ばしにするきらいがある\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. ～ないではおかない／～ずにはおかない — \"~ செய்யாமல் விடாது / ~ செய்யாமல் இருக்க முடியாது\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>ない-வடிவம் + ではおかない, அல்லது ない-வடிவத்தில் ない-ஐ நீக்கி + ずにはおかない — ஒரு இயற்கையான சக்தி அல்லது வலுவான உணர்ச்சி ஒரு விளைவைத் தவிர்க்க முடியாததாக ஆக்குகிறது; இரட்டை எதிர்மறை ஒரு வலுவான உறுதிமொழியாகப் புரிந்துகொள்ளப்படும்.</li>\n                                        <li>この映画は観客を感動させないではおかない (kono eiga wa kankyaku o kandou sasenai de wa okanai — இந்தத் திரைப்படம் பார்வையாளர்களை நிச்சயம் உணர்ச்சிவசப்படுத்தும்) <button class=\"speak-btn\" data-speak=\"この映画は観客を感動させないではおかない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li>彼の行動は皆を怒らせずにはおかない (kare no koudou wa mina o okorasezu niwa okanai — அவனுடைய நடத்தை அனைவரையும் கோபப்படுத்தாமல் இருக்காது).</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. ～を余儀なくされる(よぎなくされる) — \"~ செய்ய நிர்ப்பந்திக்கப்படுதல்\"</div>\n                                    <ul class=\"bullet-list\">\n                                        <li>பெயர்ச்சொல் (பெரும்பாலும் ஒரு வினைச்சொல் பெயர்ச்சொல்லாக்கப்பட்டது) + を余儀なくされる — யாருடைய கட்டுப்பாட்டிற்கும் உட்படாத சூழ்நிலைகள் விரும்பத்தகாத ஒரு விளைவை நிர்ப்பந்திக்கின்றன; செய்தி அறிக்கைகளில் பொதுவாகக் காணப்படும் ஒரு முறையான, செயப்பாட்டுத் தன்மை கொண்ட அமைப்பு.</li>\n                                        <li>台風のため、試合は中止を余儀なくされた (taifuu no tame, shiai wa chuushi o yoginaku sareta — புயலின் காரணமாக, போட்டி ரத்து செய்ய நிர்ப்பந்திக்கப்பட்டது) <button class=\"speak-btn\" data-speak=\"台風のため、試合は中止を余儀なくされた\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>நிர்ப்பந்தமான விளைவுகளையும் எதிர்மறைப் போக்குகளையும் <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் கண்டறியுங்கள், பிறகு மூன்றையும் <a href=\"#\" data-goto-tab=\"flashcards\">நினைவு அட்டைகள்</a> மூலம் சுயபரிசோதனை செய்யுங்கள்.</p>\n                                </div>\n                            </div>","day-pane-35":"<div class=\"glass-card\">\n                                <div class=\"card-title\">\n                                    <i class=\"fa-solid fa-newspaper\" style=\"color: var(--accent-pink);\"></i> N1·6: தலையங்கத்தைப் படித்தல்\n                                    <span class=\"badge\">இலக்கணம்</span>\n                                </div>\n                                <p>N1 வாசிப்புத் திறன் தேர்வுகள் 論説文 — கருத்துக் கட்டுரைகள் மற்றும் செய்தித்தாள் தலையங்கங்களை பெரிதும் சார்ந்திருக்கின்றன. அவற்றின் வழக்கமான சொற்றொடர்களையும் இணைப்புச் சொற்களையும் தெரிந்துகொள்வது, முறையான எழுத்தின் அடர்த்தியான சுவரை ஒரு கணிக்கக்கூடிய வாத அமைப்பாக மாற்றிவிடும். இரண்டு கெய்கோ குழிகளுடன் இந்தப் பாடம் நிறைவடைகிறது.</p>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">1. தலையங்க வழக்கமான சொற்றொடர்கள் (論説文の決まり文句)</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>～と言わざるを得ない</strong> (to iwazaru o enai — சொல்லாமல்/முடிவு செய்யாமல் இருக்க முடியாது): この結果は失敗だったと言わざるを得ない (kono kekka wa shippai datta to iwazaru o enai — இந்த முடிவு தோல்வியடைந்தது என்று ஒப்புக்கொள்ளாமல் வேறு வழியில்லை) <button class=\"speak-btn\" data-speak=\"この結果は失敗だったと言わざるを得ない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                        <li><strong>～ではなかろうか</strong> (de wa nakarou ka — ...இல்லையா என்ன?): ஒரு கருத்தை சொல்லாட்சி வினாவாக மென்மையான, முறையான வழியில் தெரிவிக்கும் வடிவம். それは杞憂ではなかろうか (sore wa kiyuu de wa nakarou ka — அது தேவையற்ற கவலை இல்லையா என்ன?)</li>\n                                        <li><strong>～に他ならない</strong> (ni hoka naranai — வேறு எதுவும் இல்லை, இதுவே): 彼の成功は努力の賜物に他ならない (kare no seikou wa doryoku no tamamono ni hoka naranai — அவனுடைய வெற்றி முயற்சியின் பலனே தவிர வேறு எதுவும் இல்லை) <button class=\"speak-btn\" data-speak=\"彼の成功は努力の賜物に他ならない\"><i class=\"fa-solid fa-volume-high\"></i></button></li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">2. முறையான இணைப்புச் சொற்கள் — したがって, もっとも, ゆえに</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>したがって</strong> (shitagatte — ஆகவே, எனவே): முன்பு கூறியதிலிருந்து தர்க்கரீதியாக எடுக்கப்பட்ட ஒரு முடிவை இணைக்கிறது, だから-ஐ விட முறையானது.</li>\n                                        <li><strong>もっとも</strong> (mottomo — எனினும், இருப்பினும்): ஒரு கூற்றைத் தொடர்ந்து ஒரு தகுதிநிபந்தனையையோ விதிவிலக்கையோ கொண்டுவந்து, முன்பு வாதிட்டதை மென்மையாக்குகிறது.</li>\n                                        <li><strong>ゆえに</strong> (yueni — ஆகையால், எனவே): மூன்றுள் மிக முறையான/தர்க்கரீதியானது, கல்வி மற்றும் சட்ட எழுத்துகளில் பொதுவாகக் காணப்படும்; பெரும்பாலும் அதற்கு முன் それ சேர்க்கப்படும் (それゆえに).</li>\n                                    </ul>\n                                </div>\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\">3. இரண்டு கெய்கோ குழிகள்</div>\n                                    <ul class=\"bullet-list\">\n                                        <li><strong>二重敬語 (இரட்டை மரியாதைச் சொல்):</strong> おっしゃられる என்பது தவறு — ஏற்கனவே மரியாதைச் சொல்லான おっしゃる (சொல்லுதல்) மேல் மீண்டும் ～られる எனும் மரியாதை விகுதியைச் சேர்த்துவிடுகிறது. おっしゃる என மட்டும் சொல்லுங்கள், அல்லது 言われる என்று சொல்லுங்கள்.</li>\n                                        <li><strong>伺う vs 参る</strong> (இரண்டுமே பணிவான \"செல்லுதல்/வருதல்\" எனினும் ஒன்றுக்கொன்று மாற்றாகப் பயன்படுத்த முடியாது): 伺う (ukagau) என்பது தன்னைவிட உயர்ந்த அந்தஸ்துடையவரைப் பார்க்கச் செல்வதையோ, கேட்பதையோ, அவரிடமிருந்து கேட்பதையோ குறிக்கும் — மற்றவரை நோக்கிய திசையுடையது. 参る (mairu) என்பது அத்தகைய திசை எதுவும் இல்லாத ஒரு எளிய பணிவான \"செல்லுதல்/வருதல்\" ஆகும், பொது வணிகப் பயன்பாட்டிற்கு ஏற்றது: 今参ります (ima mairimasu — நான் இப்போதே வருகிறேன்).</li>\n                                    </ul>\n                                </div>\n\n                                <div class=\"grammar-card\">\n                                    <div class=\"grammar-card-title\"><i class=\"fa-solid fa-dumbbell\"></i> நீங்கள் கற்றதைப் பயிற்சி செய்யுங்கள்</div>\n                                    <p>இந்தத் தலையங்க அமைப்புகளை கண்டறியும் பயிற்சியை <a href=\"#\" data-goto-tab=\"arena\">குவெஸ்ட் அரங்கம்</a>-இல் செய்யுங்கள், பிறகு முழு கெய்கோ படிநிலையையும் <a href=\"#\" data-goto-tab=\"bridge\">மும்மொழி பாலம்</a>-இல் மறுபார்வையிடுங்கள்.</p>\n                                </div>\n                            </div>"};
